1	import { _decorator, Component, Node, Prefab, Vec3, sp, error, log, tween, Tween } from 'cc';
2	import { AudioManager } from '../Audio/AudioManager';
3	import { BombInfo,  BombSymbolId, BombEffectSign } from '../Game_Define';
4	import GameView from '../GameView';
5	import { Define } from 'db://astarte-framework/utilis';
6	import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
7	import { ScatterSpine } from '../Spine/ScatterSpine';
8	import { PrefabPoolManager } from './PrefabPoolManager';
9	import { eventManager } from 'db://astarte-framework/Managers';
10	
11	const { ccclass, property } = _decorator;
12	
13	@ccclass('FeatureBomb')
14	export class FeatureBomb extends Component {
15	    @property({ type: Prefab })
16	    private m_redBombPrefab: Prefab = null;
17	
18	    @property({ type: Prefab })
19	    private m_blackBombPrefab: Prefab = null;
20	
21	    @property({ type: Node })
22	    private m_animLayerNode: Node = null;
23	
24	    @property({ type: Prefab })
25	    private m_bombEffectPrefab: Prefab = null;
26	
27	    @property({ type: Node })
28	    private m_bombEffectLayer: Node = null;
29	
30	    /**@ch 事件委派 */
31	    public eventStartBombEffect: Function[] = [];
32	    public eventStopBombEffect: Function[] = [];
33	    public eventFinished: Function[] = [];
34	
35	    /**@ch 炸彈開始事件 */
36	    static readonly EVENT_BOMB_START = 'Bomb_Start';
37	    /**@ch 炸彈火花開始事件 */
38	    static readonly EVENT_BOMB_FIRE_START = 'Bomb_Fire_Start';
39	    /**@ch 炸彈停止事件 */
40	    static readonly EVENT_BOMB_STOP = 'Bomb_Stop';
41	    /**@ch 炸彈完成事件 */
42	    static readonly EVENT_BOMB_FINISHED = 'Bomb_Finished';
43	
44	    /**@ch 炸彈資訊 */
45	    private m_bombInfos: BombInfo[] = [];
46	    /**@ch 是否正在播放 */
47	    private m_isPlaying: boolean = false;
48	    /**@ch 物件池管理器 */
49	    private m_poolManager: PrefabPoolManager = null;
50	
51	    /**@ch 音效名稱 */
52	    private readonly BOMB_CROSS = 'G97_Bomb_Cross';
53	    private readonly BOMB_JIUGONGGE = 'G97_Bomb_Jiugongge';
54	
55	    /**@ch 炸彈Win_Loop動畫播放次數 */
56	    private readonly BOMB_WIN_LOOP_COUNT = 3;
57	
58	    /**@ch 炸彈效果開始前的準備時間（秒） */
59	    private readonly BOMB_EFFECT_PREPARE_TIME = 0.3;
60	
61	    /**@ch 轉輪行數（垂直方向格子數量） */
62	    private readonly REEL_ROWS = 3;
63	
64	    /**@ch 轉輪最後一行索引 */
65	    private readonly LAST_ROW_INDEX = this.REEL_ROWS - 1;
66	
67	    /**@ch 總格子數 */
68	    private readonly TOTAL_POSITIONS = 15;
69	
70	    /**@ch 炸彈縮放比例 */
71	    private readonly BOMB_SCALE = 1.5;
72	
73	    /**@ch 炸彈晃動參數 */
74	    private readonly SHAKE_INTENSITY = 5;  // 晃動強度（像素）
75	    private readonly SHAKE_FREQUENCY = 0.15; // 晃動頻率（秒）
76	
77	    /**@ch Tween 管理 - 追蹤所有活躍的動畫 */
78	    private m_activeTweens: Map<Node, Tween<Node>> = new Map();
79	
80	    /**@ch 可重用的 Vec3 物件，避免每次晃動都創建新物件 */
81	    private m_tempShakeVec3: Vec3 = new Vec3();
82	
83	    protected onLoad(): void {
84	        if (this.m_poolManager === null) {
85	            this.m_poolManager = PrefabPoolManager.GetInstance();
86	        }
87	    }
88	
89	    protected onDestroy(): void {
90	        // 清理所有活躍的 tween
91	        this.StopAllTweens();
92	
93	        // 清理物件池
94	        if (this.m_poolManager) {
95	            this.m_poolManager.ClearPool('redBomb');
96	            this.m_poolManager.ClearPool('blackBomb');
97	            this.m_poolManager.ClearPool('bombEffect');
98	        }
99	    }
100	
101	    /**@ch 是否正在播放 */
102	    public get IsPlaying(): boolean {
103	        return this.m_isPlaying;
104	    }
105	
106	    private m_gameView: GameView = null;
107	
108	    /**@ch 初始化 */
109	    public Init(gameView: GameView)
110	    {
111	        this.m_gameView = gameView;
112	        this.m_poolManager = PrefabPoolManager.GetInstance();
113	        
114	        // 註冊 Prefab 到物件池管理器
115	        if (this.m_poolManager) {
116	            this.m_poolManager.RegisterPrefab('redBomb', this.m_redBombPrefab);
117	            this.m_poolManager.RegisterPrefab('blackBomb', this.m_blackBombPrefab);
118	            this.m_poolManager.RegisterPrefab('bombEffect', this.m_bombEffectPrefab, 8);
119	        }
120	    }
121	
122	    /**
123	     * 解析炸彈資訊 - 使用新協議格式
124	     * @param data 伺服器傳來的炸彈資料 (IBombInfo[] 陣列)
125	     */
126	    private ParseBombInfo(data: any): void {
127	        this.m_bombInfos = [];
128	        
129	        if (!Array.isArray(data)) {
130	            error('FeatureBomb: Invalid bomb data format, expected IBombInfo array');
131	            return;
132	        }
133	
134	        for (let i = 0; i < data.length; i++) {
135	            const bombData = data[i];
136	            const info: BombInfo = {
137	                bomb_id: bombData.BombSymbol,     // 新協議 BombSymbol
138	                bomb_pos: bombData.BombPos,       // 新協議 BombPos
139	                change_id: bombData.ChangeSymbol, // 新協議 ChangeSymbol
140	                change_pos: bombData.ChangePos    // 新協議 ChangePos
141	            };
142	            this.m_bombInfos.push(info);
143	        }
144	        
145	        log('FeatureBomb ParseBombInfo:', this.m_bombInfos);
146	    }
147	
148	    /**
149	     * 開始炸彈功能
150	     * @param data 炸彈資料
151	     */
152	    public StartFeature(data: any): void {
153	        this.m_isPlaying = true;
154	        log('FeatureBomb StartFeature:', data);
155	        this.ParseBombInfo(data);
156	    }
157	
158	    /**
159	     * 播放炸彈功能
160	     */
161	    public async PlayFeature(): Promise<void> {
162	        log('FeatureBomb PlayFeature started');
163	        return this.PlayBombEffectByData(() => {
164	            this.PlayEnding();
165	        });
166	    }
167	
168	    /**
169	     * 結束炸彈功能
170	     */
171	    public PlayEnding(): void {
172	        log('FeatureBomb PlayEnding');
173	        this.m_isPlaying = false;
174	        
175	        // 觸發結束事件
176	        this.eventFinished.forEach(callback => {
177	            if (callback) callback(this);
178	        });
179	
180	        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_FINISHED);
181	    }
182	
183	    /**
184	     * 根據資料播放炸彈效果
185	     * @param callback 完成回調
186	     */
187	    private async PlayBombEffectByData(callback: Function): Promise<void> {
188	        const promises = this.m_bombInfos.map(async (info) => {
189	            // log('FeatureBomb playBombEffectByData:', info);
190	            
191	            // 等待炸彈效果開始前的準備時間
192	            await this.WaitForSeconds(this.BOMB_EFFECT_PREPARE_TIME);
193	            
194	            // 觸發開始事件
195	            this.eventStartBombEffect.forEach(callback => {
196	                if (callback) callback(info.bomb_pos);
197	            });
198	
199	            eventManager.Dispatch(FeatureBomb.EVENT_BOMB_START);
200	            
201	            // 隱藏原符號
202	            this.ShowSymbol(info.bomb_pos, false);
203	            
204	            // 根據炸彈類型播放不同音效和更換符號
205	            if (info.bomb_id === BombSymbolId.RedBomb) {
206	                AudioManager.Play(this.BOMB_JIUGONGGE, false, null, 1);
207	                this.ChangeSymbol(BombSymbolId.RedBomb, info.bomb_pos);
208	            } else {
209	                AudioManager.Play(this.BOMB_CROSS, false, null, 1);
210	                this.ChangeSymbol(BombSymbolId.BlackBomb, info.bomb_pos);
211	            }
212	
213	            // 播放炸彈爆炸動畫
214	            const callback1 = () => {
215	                
216	            };
217	            await this.PlayBombEffect(info.bomb_id, info.bomb_pos, callback1);
218	
219	            eventManager.Dispatch(FeatureBomb.EVENT_BOMB_FIRE_START);
220	
221	            // 播放火花效果
222	            const callback2 = () => {
223	                this.ShowSymbol(info.bomb_pos, true);
224	                this.ChangeSymbol(info.change_id, info.bomb_pos);
225	                info.change_pos.forEach((pos) => {
226	                    this.ChangeSymbol(info.change_id, pos);
227	                });
228	            };
229	            await this.PlayFireEffect(info.bomb_id, info.bomb_pos, callback2);
230	        });
231	
232	        await Promise.all(promises);
233	        
234	        // 觸發停止事件
235	        this.eventStopBombEffect.forEach(callback => {
236	            if (callback) callback();
237	        });
238	
239	        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_STOP);
240	        
241	        if (callback) {
242	            callback();
243	        }
244	    }
245	
246	    /**
247	     * 取得指定位置的初始世界座標
248	     * @param blockID 轉輪位置編號
249	     * @returns 世界座標
250	     */
251	    private GetBlockWorldPosition(blockID: number): Vec3 {
252	        if (!this.m_gameView.SinglePlateMgr) {
253	            error('GetBlockWorldPosition: SinglePlateMgr is null');
254	            return Vec3.ZERO;
255	        }
256	
257	        // 透過 SinglePlateMgr 取得位置
258	        return this.m_gameView.SinglePlateMgr.GetSymbolInitWorldPositionByPosition(blockID);
259	    }
260	
261	    /**
262	     * 播放炸彈爆炸效果
263	     * @param bombId 炸彈 ID
264	     * @param bombLocation 炸彈位置
265	     * @param callback 回調函式
266	     */
267	    private PlayBombEffect(bombId: number, bombLocation: number, callback: Function): Promise<void> {
268	        return new Promise<void>((resolve) => {
269	            (async () => {
270	                // 取得炸彈位置
271	                const bombWorldPos = this.GetBlockWorldPosition(bombLocation);
272	                const bombKey = bombId === BombSymbolId.RedBomb ? 'redBomb' : 'blackBomb';
273	
274	                if (!this.m_poolManager) {
275	                    error('PlayBombEffect: Pool manager is null');
276	                    resolve();
277	                    return;
278	                }
279	
280	                // 使用物件池管理器取得炸彈節點
281	                const bombNode = this.m_poolManager.GetNode(bombKey, this.m_bombEffectLayer);
282	                if (!bombNode) {
283	                    error('PlayBombEffect: Failed to get bomb node');
284	                    resolve();
285	                    return;
286	                }
287	                bombNode.setWorldPosition(bombWorldPos);
288	                bombNode.setScale(this.BOMB_SCALE, this.BOMB_SCALE, 1);
289	
290	                // 取得 Spine 組件
291	                const bombEffect = bombNode.getComponent(ScatterSpine);
292	                if (!bombEffect) {
293	                    error('PlayBombEffect: Spine component not found');
294	                    this.m_poolManager.ReturnNode(bombKey, bombNode);
295	                    resolve();
296	                    return;
297	                }
298	
299	                // 計算 Win_Loop 總播放時間
300	                const winLoopTotalDuration = this.BOMB_WIN_LOOP_COUNT * 0.3; // 假設每次 Win_Loop 約 1 秒
301	                
302	                const shakePromise = this.PlayBombShakeEffect(bombNode, winLoopTotalDuration);
303	
304	                // 同時播放 Win_Loop 動畫和晃動效果
305	                const winLoopPromise = (async () => {
306	                    for (let i = 0; i < this.BOMB_WIN_LOOP_COUNT; i++) {
307	                        await bombEffect.PlayAnimation("Win_Loop");
308	                        // log('PlayBombEffect win_loop_count:', i + 1);
309	                    }
310	                })();
311	                
312	                // 等待兩個效果都完成
313	                await Promise.all([winLoopPromise, shakePromise]);
314	
315	                // 在延遲後呼叫 callback，並於此刻讓呼叫端繼續往下執行
316	                this.DelayToProcess(0.2, () => {
317	                    if (callback) callback();
318	                    resolve();
319	                });
320	
321	                try {                    
322	                    // 播放 Win_End 動畫並監聽事件（在背景持續，與呼叫端解綁）
323	                    await bombEffect.PlayAnimation("Win_End", bombEffect.Spine, false, 1, (eventName: string) => {
324	                        // log('Bomb Hit event trigger:', eventName);
325	                    });
326	                } finally {
327	                    // 歸還節點到物件池
328	                    this.m_poolManager.ReturnNode(bombKey, bombNode);
329	                    log('PlayBombEffect complete');
330	                }
331	            })().catch((e) => {
332	                error('PlayBombEffect error:', e);
333	                resolve();
334	            });
335	        });
336	    }
337	
338	    /**
339	     * 更換指定位置的符號
340	     * @param changeId 要更換的符號 ID
341	     * @param changePos 要更換的位置
342	     */
343	    private ChangeSymbol(changeId: number, changePos: number): void {
344	        if (!this.m_gameView.SinglePlateMgr) {
345	            error('ChangeSymbol: SinglePlateMgr is null');
346	            return;
347	        }
348	
349	        // 透過 SinglePlateMgr 更換符號
350	        this.m_gameView.SinglePlateMgr.ChangeSymbolByPosition(changePos, changeId);
351	    }
352	
353	    /**
354	     * 顯示或隱藏指定位置的符號
355	     * @param changePos 位置
356	     * @param isShow 是否顯示
357	     */
358	    private ShowSymbol(changePos: number, isShow: boolean): void {
359	        if (!this.m_gameView.SinglePlateMgr) {
360	            error('ShowSymbol: SinglePlateMgr is null');
361	            return;
362	        }
363	
364	        // 透過 SinglePlateMgr 顯示/隱藏符號
365	        this.m_gameView.SinglePlateMgr.SetSymbolShowByPosition(changePos, isShow);
366	    }
367	
368	    /**
369	     * 檢查位置是否存在於 8 個方向
370	     * @param pos 位置
371	     * @returns 8 個方向的存在性陣列
372	     */
373	    private CheckPosExist(pos: number): boolean[] {
374	        const posExist = [false, false, false, false, false, false, false, false];
375	        
376	        const hasTop = pos % this.REEL_ROWS !== 0;        // 0,3,6,9,12
377	        const hasDown = pos % this.REEL_ROWS !== this.LAST_ROW_INDEX;       // 2,5,8,11,14
378	        const hasLeft = pos >= this.REEL_ROWS;            // 0,1,2
379	        const hasRight = pos <= (this.TOTAL_POSITIONS - this.REEL_ROWS - 1);          // 12,13,14
380	        
381	        posExist[BombEffectSign.Up] = hasTop;
382	        posExist[BombEffectSign.Down] = hasDown;
383	        posExist[BombEffectSign.Left] = hasLeft;
384	        posExist[BombEffectSign.Right] = hasRight;
385	        posExist[BombEffectSign.LeftUp] = hasTop && hasLeft;
386	        posExist[BombEffectSign.LeftDown] = hasDown && hasLeft;
387	        posExist[BombEffectSign.RightUp] = hasTop && hasRight;
388	        posExist[BombEffectSign.RightDown] = hasDown && hasRight;
389	        
390	        return posExist;
391	    }
392	
393	    /**
394	     * 播放單個火花動畫的通用方法
395	     * @param animationName 動畫名稱
396	     * @param position 世界位置
397	     * @param eventCallback 事件回調函式
398	     * @returns Promise<void>
399	     */
400	    private PlaySingleFireAnimation(animationName: string, position: Vec3, eventCallback?: Function): Promise<void> {
401	        return new Promise<void>((resolve) => {
402	            if (!this.m_bombEffectPrefab) {
403	                error('PlaySingleFireAnimation: Bomb effect prefab is null');
404	                resolve();
405	                return;
406	            }
407	
408	            // 從物件池取得特效節點
409	            const effectNode = this.m_poolManager.GetNode('bombEffect', this.m_animLayerNode);
410	            if (!effectNode) {
411	                error('PlaySingleFireAnimation: Failed to get effect node');
412	                resolve();
413	                return;
414	            }
415	
416	            // 設定位置
417	            effectNode.setWorldPosition(position);
418	
419	            // 播放特效
420	            const bombEffect = effectNode.getComponent(sp.Skeleton);
421	            if (!bombEffect) {
422	                error('PlaySingleFireAnimation: Spine component not found');
423	                this.m_poolManager.ReturnNode('bombEffect', effectNode);
424	                resolve();
425	                return;
426	            }
427	
428	            // 播放動畫
429	            SpineKit.PlayAnimation(bombEffect, animationName, false, 0, (eventName: string) => {
430	                if (eventName === "Hit" && eventCallback) {
431	                    eventCallback();
432	                }
433	            }).then(() => {
434	                // 動畫完成後歸還節點到物件池
435	                this.m_poolManager.ReturnNode('bombEffect', effectNode);
436	                resolve();
437	            }).catch((e) => {
438	                error('PlaySingleFireAnimation animation error:', e);
439	                this.m_poolManager.ReturnNode('bombEffect', effectNode);
440	                resolve();
441	            });
442	        });
443	    }
444	
445	    /**
446	     * 播放中心火花效果
447	     * @param bombLocation 炸彈位置
448	     * @param callback 回調函式
449	     * @returns Promise<void>
450	     */
451	    private PlayCenterFireEffect(bombLocation: number, callback?: Function): Promise<void> {
452	        const bombPos = this.GetBlockWorldPosition(bombLocation);
453	        return this.PlaySingleFireAnimation("M", bombPos, callback);
454	    }
455	
456	    /**
457	     * 播放火花效果
458	     * @param bombId 炸彈 ID
459	     * @param bombLocation 炸彈位置
460	     * @param callback 回調函式
461	     */
462	    private async PlayFireEffect(bombId: number, bombLocation: number, callback: Function): Promise<void> {
463	        const redBombSpineList = ["T", "D", "L", "R", "LT", "LD", "RT", "RD"];
464	        const blackBombSpineList = ["T", "D", "L", "R"];
465	        const bombSpineList = bombId === BombSymbolId.RedBomb ? redBombSpineList : blackBombSpineList;
466	
467	        const bombPos = this.GetBlockWorldPosition(bombLocation);
468	        const posExist = this.CheckPosExist(bombLocation);
469	
470	        // log('PlayFireEffect posExist:', posExist);
471	
472	        let regEvent = false;
473	        const effectPromises: Promise<void>[] = [];
474	
475	        // 增加中心爆炸效果
476	        const centerEffectPromise = this.PlayCenterFireEffect(bombLocation, () => {
477	            if (!regEvent) {
478	                regEvent = true;
479	                log('Bomb Center Fire Hit event trigger');
480	                if (callback) callback();
481	            }
482	        });
483	        effectPromises.push(centerEffectPromise);
484	
485	        // 播放方向性火花效果
486	        for (let index = 0; index < bombSpineList.length; index++) {
487	            const animationName = bombSpineList[index];
488	
489	            if (!posExist[index]) {
490	                continue;
491	            }
492	
493	            // 使用通用方法播放方向性火花動畫
494	            const effectPromise = this.PlaySingleFireAnimation(animationName, bombPos, () => {
495	                if (!regEvent) {
496	                    regEvent = true;
497	                    log('Bomb Fire Hit event trigger');
498	                    if (callback) callback();
499	                }
500	            });
501	
502	            effectPromises.push(effectPromise);
503	        }
504	
505	        // 等待所有特效動畫完成
506	        await Promise.all(effectPromises);
507	    }
508	
509	    /**
510	     * 等待指定秒數
511	     * @param seconds 秒數
512	     */
513	    private WaitForSeconds(seconds: number): Promise<void> {
514	        return Define.Wait( this, seconds);
515	    }
516	
517	    /**
518	     * 延遲處理
519	     * @param seconds 秒數
520	     * @param callback 回調函式
521	     */
522	    private DelayToProcess(seconds : number, callback : Function)
523	    {
524	        Define.Wait(this, seconds).then(() => {
525	            if (callback) callback();
526	        });
527	    }
528	
529	    /**
530	     * 播放炸彈節點晃動效果（優化版 - 帶 Tween 管理）
531	     * @param bombNode 炸彈節點
532	     * @param duration 晃動持續時間（秒）
533	     * @returns Promise
534	     */
535	    private PlayBombShakeEffect(bombNode: Node, duration: number): Promise<void> {
536	        return new Promise<void>((resolve) => {
537	            if (!bombNode || !bombNode.isValid) {
538	                resolve();
539	                return;
540	            }
541	
542	            // 停止該節點上的舊 tween
543	            this.StopNodeTween(bombNode);
544	
545	            // 記錄原始位置
546	            const originalPosition = bombNode.position.clone();
547	            let shakeCount = 0;
548	            const totalShakes = Math.floor(duration / this.SHAKE_FREQUENCY);
549	
550	            // 創建晃動循環
551	            const performShake = () => {
552	                // 檢查節點是否仍然有效
553	                if (!bombNode.isValid || shakeCount >= totalShakes) {
554	                    // 晃動結束，回到原始位置
555	                    const finalTween = tween(bombNode)
556	                        .to(0.05, { position: originalPosition })
557	                        .call(() => {
558	                            this.m_activeTweens.delete(bombNode);
559	                            resolve();
560	                        })
561	                        .start();
562	
563	                    this.m_activeTweens.set(bombNode, finalTween);
564	                    return;
565	                }
566	
567	                // 計算隨機偏移（使用可重用的 Vec3，避免每次晃動都創建新物件）
568	                const offsetX = (Math.random() - 0.5) * 2 * this.SHAKE_INTENSITY;
569	                const offsetY = (Math.random() - 0.5) * 2 * this.SHAKE_INTENSITY;
570	                this.m_tempShakeVec3.set(
571	                    originalPosition.x + offsetX,
572	                    originalPosition.y + offsetY,
573	                    originalPosition.z
