import { _decorator, Component, Node, Prefab, Vec3, sp, error, log, tween, Tween } from 'cc';
import { AudioManager } from '../Audio/AudioManager';
import { BombInfo,  BombSymbolId, BombEffectSign } from '../Game_Define';
import GameView from '../GameView';
import { Define } from 'db://astarte-framework/utilis';
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import { ScatterSpine } from '../Spine/ScatterSpine';
import { PrefabPoolManager } from './PrefabPoolManager';
import { eventManager } from 'db://astarte-framework/Managers';

const { ccclass, property } = _decorator;

@ccclass('FeatureBomb')
export class FeatureBomb extends Component {
    @property({ type: Prefab })
    private m_redBombPrefab: Prefab = null;

    @property({ type: Prefab })
    private m_blackBombPrefab: Prefab = null;

    @property({ type: Node })
    private m_animLayerNode: Node = null;

    @property({ type: Prefab })
    private m_bombEffectPrefab: Prefab = null;

    @property({ type: Node })
    private m_bombEffectLayer: Node = null;

    /**@ch 事件委派 */
    public eventStartBombEffect: Function[] = [];
    public eventStopBombEffect: Function[] = [];
    public eventFinished: Function[] = [];

    /**@ch 炸彈開始事件 */
    static readonly EVENT_BOMB_START = 'Bomb_Start';
    /**@ch 炸彈火花開始事件 */
    static readonly EVENT_BOMB_FIRE_START = 'Bomb_Fire_Start';
    /**@ch 炸彈停止事件 */
    static readonly EVENT_BOMB_STOP = 'Bomb_Stop';
    /**@ch 炸彈完成事件 */
    static readonly EVENT_BOMB_FINISHED = 'Bomb_Finished';

    /**@ch 炸彈資訊 */
    private m_bombInfos: BombInfo[] = [];
    /**@ch 是否正在播放 */
    private m_isPlaying: boolean = false;
    /**@ch 物件池管理器 */
    private m_poolManager: PrefabPoolManager = null;

    /**@ch 音效名稱 */
    private readonly BOMB_CROSS = 'G97_Bomb_Cross';
    private readonly BOMB_JIUGONGGE = 'G97_Bomb_Jiugongge';

    /**@ch 炸彈Win_Loop動畫播放次數 */
    private readonly BOMB_WIN_LOOP_COUNT = 3;

    /**@ch 炸彈效果開始前的準備時間（秒） */
    private readonly BOMB_EFFECT_PREPARE_TIME = 0.3;

    /**@ch 轉輪行數（垂直方向格子數量） */
    private readonly REEL_ROWS = 3;

    /**@ch 轉輪最後一行索引 */
    private readonly LAST_ROW_INDEX = this.REEL_ROWS - 1;

    /**@ch 總格子數 */
    private readonly TOTAL_POSITIONS = 15;

    /**@ch 炸彈縮放比例 */
    private readonly BOMB_SCALE = 1.5;

    /**@ch 炸彈晃動參數 */
    private readonly SHAKE_INTENSITY = 5;  // 晃動強度（像素）
    private readonly SHAKE_FREQUENCY = 0.15; // 晃動頻率（秒）

    /**@ch Tween 管理 - 追蹤所有活躍的動畫 */
    private m_activeTweens: Map<Node, Tween<Node>> = new Map();

    /**@ch 可重用的 Vec3 物件，避免每次晃動都創建新物件 */
    private m_tempShakeVec3: Vec3 = new Vec3();

    protected onLoad(): void {
        if (this.m_poolManager === null) {
            this.m_poolManager = PrefabPoolManager.GetInstance();
        }
    }

    protected onDestroy(): void {
        // 清理所有活躍的 tween
        this.StopAllTweens();

        // 清理物件池
        if (this.m_poolManager) {
            this.m_poolManager.ClearPool('redBomb');
            this.m_poolManager.ClearPool('blackBomb');
            this.m_poolManager.ClearPool('bombEffect');
        }
    }

    /**@ch 是否正在播放 */
    public get IsPlaying(): boolean {
        return this.m_isPlaying;
    }

    private m_gameView: GameView = null;

    /**@ch 初始化 */
    public Init(gameView: GameView)
    {
        this.m_gameView = gameView;
        this.m_poolManager = PrefabPoolManager.GetInstance();

        // 註冊 Prefab 到物件池管理器
        if (this.m_poolManager) {
            this.m_poolManager.RegisterPrefab('redBomb', this.m_redBombPrefab);
            this.m_poolManager.RegisterPrefab('blackBomb', this.m_blackBombPrefab);
            this.m_poolManager.RegisterPrefab('bombEffect', this.m_bombEffectPrefab, 8);
        }
    }

    /**
     * 解析炸彈資訊 - 使用新協議格式
     * @param data 伺服器傳來的炸彈資料 (IBombInfo[] 陣列)
     */
    private ParseBombInfo(data: any): void {
        this.m_bombInfos = [];

        if (!Array.isArray(data)) {
            error('FeatureBomb: Invalid bomb data format, expected IBombInfo array');
            return;
        }

        for (let i = 0; i < data.length; i++) {
            const bombData = data[i];
            const info: BombInfo = {
                bomb_id: bombData.BombSymbol,     // 新協議 BombSymbol
                bomb_pos: bombData.BombPos,       // 新協議 BombPos
                change_id: bombData.ChangeSymbol, // 新協議 ChangeSymbol
                change_pos: bombData.ChangePos    // 新協議 ChangePos
            };
            this.m_bombInfos.push(info);
        }

        log('FeatureBomb ParseBombInfo:', this.m_bombInfos);
    }

    /**
     * 開始炸彈功能
     * @param data 炸彈資料
     */
    public StartFeature(data: any): void {
        this.m_isPlaying = true;
        log('FeatureBomb StartFeature:', data);
        this.ParseBombInfo(data);
    }

    /**
     * 播放炸彈功能
     */
    public async PlayFeature(): Promise<void> {
        log('FeatureBomb PlayFeature started');
        return this.PlayBombEffectByData(() => {
            this.PlayEnding();
        });
    }

    /**
     * 結束炸彈功能
     */
    public PlayEnding(): void {
        log('FeatureBomb PlayEnding');
        this.m_isPlaying = false;

        // 觸發結束事件
        this.eventFinished.forEach(callback => {
            if (callback) callback(this);
        });

        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_FINISHED);
    }

    /**
     * 根據資料播放炸彈效果
     * @param callback 完成回調
     */
    private async PlayBombEffectByData(callback: Function): Promise<void> {
        const promises = this.m_bombInfos.map(async (info) => {
            // log('FeatureBomb playBombEffectByData:', info);

            // 等待炸彈效果開始前的準備時間
            await this.WaitForSeconds(this.BOMB_EFFECT_PREPARE_TIME);

            // 觸發開始事件
            this.eventStartBombEffect.forEach(callback => {
                if (callback) callback(info.bomb_pos);
            });

            eventManager.Dispatch(FeatureBomb.EVENT_BOMB_START);

            // 隱藏原符號
            this.ShowSymbol(info.bomb_pos, false);

            // 根據炸彈類型播放不同音效和更換符號
            if (info.bomb_id === BombSymbolId.RedBomb) {
                AudioManager.Play(this.BOMB_JIUGONGGE, false, null, 1);
                this.ChangeSymbol(BombSymbolId.RedBomb, info.bomb_pos);
            } else {
                AudioManager.Play(this.BOMB_CROSS, false, null, 1);
                this.ChangeSymbol(BombSymbolId.BlackBomb, info.bomb_pos);
            }

            // 播放炸彈爆炸動畫
            const callback1 = () => {

            };
            await this.PlayBombEffect(info.bomb_id, info.bomb_pos, callback1);

            eventManager.Dispatch(FeatureBomb.EVENT_BOMB_FIRE_START);

            // 播放火花效果
            const callback2 = () => {
                this.ShowSymbol(info.bomb_pos, true);
                this.ChangeSymbol(info.change_id, info.bomb_pos);
                info.change_pos.forEach((pos) => {
                    this.ChangeSymbol(info.change_id, pos);
                });
            };
            await this.PlayFireEffect(info.bomb_id, info.bomb_pos, callback2);
        });

        await Promise.all(promises);

        // 觸發停止事件
        this.eventStopBombEffect.forEach(callback => {
            if (callback) callback();
        });

        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_STOP);

        if (callback) {
            callback();
        }
    }

    /**
     * 取得指定位置的初始世界座標
     * @param blockID 轉輪位置編號
     * @returns 世界座標
     */
    private GetBlockWorldPosition(blockID: number): Vec3 {
        if (!this.m_gameView.SinglePlateMgr) {
            error('GetBlockWorldPosition: SinglePlateMgr is null');
            return Vec3.ZERO;
        }

        // 透過 SinglePlateMgr 取得位置
        return this.m_gameView.SinglePlateMgr.GetSymbolInitWorldPositionByPosition(blockID);
    }

    /**
     * 播放炸彈爆炸效果
     * @param bombId 炸彈 ID
     * @param bombLocation 炸彈位置
     * @param callback 回調函式
     */
    private PlayBombEffect(bombId: number, bombLocation: number, callback: Function): Promise<void> {
        return new Promise<void>((resolve) => {
            (async () => {
                // 取得炸彈位置
                const bombWorldPos = this.GetBlockWorldPosition(bombLocation);
                const bombKey = bombId === BombSymbolId.RedBomb ? 'redBomb' : 'blackBomb';

                if (!this.m_poolManager) {
                    error('PlayBombEffect: Pool manager is null');
                    resolve();
                    return;
                }

                // 使用物件池管理器取得炸彈節點
                const bombNode = this.m_poolManager.GetNode(bombKey, this.m_bombEffectLayer);
                if (!bombNode) {
                    error('PlayBombEffect: Failed to get bomb node');
                    resolve();
                    return;
                }
                bombNode.setWorldPosition(bombWorldPos);
                bombNode.setScale(this.BOMB_SCALE, this.BOMB_SCALE, 1);

                // 取得 Spine 組件
                const bombEffect = bombNode.getComponent(ScatterSpine);
                if (!bombEffect) {
                    error('PlayBombEffect: Spine component not found');
                    this.m_poolManager.ReturnNode(bombKey, bombNode);
                    resolve();
                    return;
                }

                // 計算 Win_Loop 總播放時間
                const winLoopTotalDuration = this.BOMB_WIN_LOOP_COUNT * 0.3; // 假設每次 Win_Loop 約 1 秒

                const shakePromise = this.PlayBombShakeEffect(bombNode, winLoopTotalDuration);

                // 同時播放 Win_Loop 動畫和晃動效果
                const winLoopPromise = (async () => {
                    for (let i = 0; i < this.BOMB_WIN_LOOP_COUNT; i++) {
                        await bombEffect.PlayAnimation("Win_Loop");
                        // log('PlayBombEffect win_loop_count:', i + 1);
                    }
                })();

                // 等待兩個效果都完成
                await Promise.all([winLoopPromise, shakePromise]);

                // 在延遲後呼叫 callback，並於此刻讓呼叫端繼續往下執行
                this.DelayToProcess(0.2, () => {
                    if (callback) callback();
                    resolve();
                });

                try {                    
                    // 播放 Win_End 動畫並監聽事件（在背景持續，與呼叫端解綁）
                    await bombEffect.PlayAnimation("Win_End", bombEffect.Spine, false, 1, (eventName: string) => {
                        // log('Bomb Hit event trigger:', eventName);
                    });
                } finally {
                    // 歸還節點到物件池
                    this.m_poolManager.ReturnNode(bombKey, bombNode);
                    log('PlayBombEffect complete');
                }
            })().catch((e) => {
                error('PlayBombEffect error:', e);
                resolve();
            });
        });
    }

    /**
     * 更換指定位置的符號
     * @param changeId 要更換的符號 ID
     * @param changePos 要更換的位置
     */
    private ChangeSymbol(changeId: number, changePos: number): void {
        if (!this.m_gameView.SinglePlateMgr) {
            error('ChangeSymbol: SinglePlateMgr is null');
            return;
        }

        // 透過 SinglePlateMgr 更換符號
        this.m_gameView.SinglePlateMgr.ChangeSymbolByPosition(changePos, changeId);
    }

    /**
     * 顯示或隱藏指定位置的符號
     * @param changePos 位置
     * @param isShow 是否顯示
     */
    private ShowSymbol(changePos: number, isShow: boolean): void {
        if (!this.m_gameView.SinglePlateMgr) {
            error('ShowSymbol: SinglePlateMgr is null');
            return;
        }

        // 透過 SinglePlateMgr 顯示/隱藏符號
        this.m_gameView.SinglePlateMgr.SetSymbolShowByPosition(changePos, isShow);
    }

    /**
     * 檢查位置是否存在於 8 個方向
     * @param pos 位置
     * @returns 8 個方向的存在性陣列
     */
    private CheckPosExist(pos: number): boolean[] {
        const posExist = [false, false, false, false, false, false, false, false];

        const hasTop = pos % this.REEL_ROWS !== 0;        // 0,3,6,9,12
        const hasDown = pos % this.REEL_ROWS !== this.LAST_ROW_INDEX;       // 2,5,8,11,14
        const hasLeft = pos >= this.REEL_ROWS;            // 0,1,2
        const hasRight = pos <= (this.TOTAL_POSITIONS - this.REEL_ROWS - 1);          // 12,13,14

        posExist[BombEffectSign.Up] = hasTop;
        posExist[BombEffectSign.Down] = hasDown;
        posExist[BombEffectSign.Left] = hasLeft;
        posExist[BombEffectSign.Right] = hasRight;
        posExist[BombEffectSign.LeftUp] = hasTop && hasLeft;
        posExist[BombEffectSign.LeftDown] = hasDown && hasLeft;
        posExist[BombEffectSign.RightUp] = hasTop && hasRight;
        posExist[BombEffectSign.RightDown] = hasDown && hasRight;

        return posExist;
    }

    /**
     * 播放單個火花動畫的通用方法
     * @param animationName 動畫名稱
     * @param position 世界位置
     * @param eventCallback 事件回調函式
     * @returns Promise<void>
     */
    private PlaySingleFireAnimation(animationName: string, position: Vec3, eventCallback?: Function): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!this.m_bombEffectPrefab) {
                error('PlaySingleFireAnimation: Bomb effect prefab is null');
                resolve();
                return;
            }

            // 從物件池取得特效節點
            const effectNode = this.m_poolManager.GetNode('bombEffect', this.m_animLayerNode);
            if (!effectNode) {
                error('PlaySingleFireAnimation: Failed to get effect node');
                resolve();
                return;
            }

            // 設定位置
            effectNode.setWorldPosition(position);

            // 播放特效
            const bombEffect = effectNode.getComponent(sp.Skeleton);
            if (!bombEffect) {
                error('PlaySingleFireAnimation: Spine component not found');
                this.m_poolManager.ReturnNode('bombEffect', effectNode);
                resolve();
                return;
            }

            // 播放動畫
            SpineKit.PlayAnimation(bombEffect, animationName, false, 0, (eventName: string) => {
                if (eventName === "Hit" && eventCallback) {
                    eventCallback();
                }
            }).then(() => {
                // 動畫完成後歸還節點到物件池
                this.m_poolManager.ReturnNode('bombEffect', effectNode);
                resolve();
            }).catch((e) => {
                error('PlaySingleFireAnimation animation error:', e);
                this.m_poolManager.ReturnNode('bombEffect', effectNode);
                resolve();
            });
        });
    }

    /**
     * 播放中心火花效果
     * @param bombLocation 炸彈位置
     * @param callback 回調函式
     * @returns Promise<void>
     */
    private PlayCenterFireEffect(bombLocation: number, callback?: Function): Promise<void> {
        const bombPos = this.GetBlockWorldPosition(bombLocation);
        return this.PlaySingleFireAnimation("M", bombPos, callback);
    }

    /**
     * 播放火花效果
     * @param bombId 炸彈 ID
     * @param bombLocation 炸彈位置
     * @param callback 回調函式
     */
    private async PlayFireEffect(bombId: number, bombLocation: number, callback: Function): Promise<void> {
        const redBombSpineList = ["T", "D", "L", "R", "LT", "LD", "RT", "RD"];
        const blackBombSpineList = ["T", "D", "L", "R"];
        const bombSpineList = bombId === BombSymbolId.RedBomb ? redBombSpineList : blackBombSpineList;

        const bombPos = this.GetBlockWorldPosition(bombLocation);
        const posExist = this.CheckPosExist(bombLocation);

        // log('PlayFireEffect posExist:', posExist);

        let regEvent = false;
        const effectPromises: Promise<void>[] = [];

        // 增加中心爆炸效果
        const centerEffectPromise = this.PlayCenterFireEffect(bombLocation, () => {
            if (!regEvent) {
                regEvent = true;
                log('Bomb Center Fire Hit event trigger');
                if (callback) callback();
            }
        });
        effectPromises.push(centerEffectPromise);

        // 播放方向性火花效果
        for (let index = 0; index < bombSpineList.length; index++) {
            const animationName = bombSpineList[index];

            if (!posExist[index]) {
                continue;
            }

            // 使用通用方法播放方向性火花動畫
            const effectPromise = this.PlaySingleFireAnimation(animationName, bombPos, () => {
                if (!regEvent) {
                    regEvent = true;
                    log('Bomb Fire Hit event trigger');
                    if (callback) callback();
                }
            });

            effectPromises.push(effectPromise);
        }

        // 等待所有特效動畫完成
        await Promise.all(effectPromises);
    }

    /**
     * 等待指定秒數
     * @param seconds 秒數
     */
    private WaitForSeconds(seconds: number): Promise<void> {
        return Define.Wait( this, seconds);
    }

    /**
     * 延遲處理
     * @param seconds 秒數
     * @param callback 回調函式
     */
    private DelayToProcess(seconds : number, callback : Function)
    {
        Define.Wait(this, seconds).then(() => {
            if (callback) callback();
        });
    }

    /**
     * 播放炸彈節點晃動效果（優化版 - 帶 Tween 管理）
     * @param bombNode 炸彈節點
     * @param duration 晃動持續時間（秒）
     * @returns Promise
     */
    private PlayBombShakeEffect(bombNode: Node, duration: number): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!bombNode || !bombNode.isValid) {
                resolve();
                return;
            }

            // 停止該節點上的舊 tween
            this.StopNodeTween(bombNode);

            // 記錄原始位置
            const originalPosition = bombNode.position.clone();
            let shakeCount = 0;
            const totalShakes = Math.floor(duration / this.SHAKE_FREQUENCY);

            // 創建晃動循環
            const performShake = () => {
                // 檢查節點是否仍然有效
                if (!bombNode.isValid || shakeCount >= totalShakes) {
                    // 晃動結束，回到原始位置
                    const finalTween = tween(bombNode)
                        .to(0.05, { position: originalPosition })
                        .call(() => {
                            this.m_activeTweens.delete(bombNode);
                            resolve();
                        })
                        .start();

                    this.m_activeTweens.set(bombNode, finalTween);
                    return;
                }

                // 計算隨機偏移（使用可重用的 Vec3，避免每次晃動都創建新物件）
                const offsetX = (Math.random() - 0.5) * 2 * this.SHAKE_INTENSITY;
                const offsetY = (Math.random() - 0.5) * 2 * this.SHAKE_INTENSITY;
                this.m_tempShakeVec3.set(
                    originalPosition.x + offsetX,
                    originalPosition.y + offsetY,
                    originalPosition.z
                );

                // 執行晃動
                const shakeTween = tween(bombNode)
                    .to(this.SHAKE_FREQUENCY, { position: this.m_tempShakeVec3 })
                    .call(() => {
                        shakeCount++;
                        performShake();
                    })
                    .start();

                this.m_activeTweens.set(bombNode, shakeTween);
            };

            // 開始晃動
            performShake();
        });
    }

    /**
     * 停止指定節點上的所有 Tween
     * @param node 目標節點
     */
    private StopNodeTween(node: Node): void {
        if (!node || !node.isValid) {
            return;
        }

        // 停止並移除追蹤的 tween
        if (this.m_activeTweens.has(node)) {
            const existingTween = this.m_activeTweens.get(node);
            existingTween?.stop();
            this.m_activeTweens.delete(node);
        }

        // 同時停止 Cocos 層面的所有 tween
        Tween.stopAllByTarget(node);
    }

    /**
     * 停止所有追蹤的 Tween
     */
    private StopAllTweens(): void {
        this.m_activeTweens.forEach((tweenInstance, node) => {
            if (tweenInstance) {
                tweenInstance.stop();
            }
        });
        this.m_activeTweens.clear();

        log('FeatureBomb: All tweens stopped and cleared');
    }
}

