327	    /**
328	     * 更新鎖定框節點縮放
329	     * @param dt 時間間隔
330	     */
331	    protected update(dt: number): void {
332	        // 只有在非IDLE狀態下才執行動畫邏輯，節省效能
333	        if (this.m_CurrentState === CrossFeverState.IDLE) {
334	            return;
335	        }
336	
337	        // 處理鎖定音效防抖重置
338	        if (this.m_lockSoundPlayed) {
339	            this.m_lockSoundTimer += dt;
340	            if (this.m_lockSoundTimer >= CrossFeverController.LOCK_SOUND_RESET_TIME) {
341	                this.m_lockSoundPlayed = false;
342	                this.m_lockSoundTimer = 0;
343	            }
344	        }
345	
346	        this.m_AnimationDt += dt;
347	        if (this.m_AnimationDt >= CrossFeverController.ANIMATION_INTERVAL) {
348	            this.m_AnimationDt = 0;
349	            this.m_AnimationFlag = !this.m_AnimationFlag;
350	
351	            const targetScale = this.m_AnimationFlag ?
352	                CrossFeverController.SCALE_ANIMATED :
353	                CrossFeverController.SCALE_NORMAL;
354	
355	            this.updateLineFramesScale(targetScale);
356	        }
357	    }
