394	    /**
395	     * 公開方法：開始CrossFever
396	     */
397	    public async StartCrossFever() {
398	        if (this.m_CurrentState !== CrossFeverState.IDLE) {
399	            warn('CrossFever already active');
400	            return;
401	        }
402	        log('Starting CrossFever');
403	
404	        // 註冊事件監聽
405	        this.RegisterEvents();
406	
407	        this.m_CurrentState = CrossFeverState.STARTING;        
408	
409	        try {
410	            // 等待0.3秒
411	            await Define.Wait(this, 0.3);
412	
413	            // 播放開場特效
414	            await this.DoCrossFeverStart();
415	            
416	            // 進入遊戲狀態
417	            this.m_CurrentState = CrossFeverState.PLAYING;
418	            
419	            // 發送開始事件
420	            eventManager.Dispatch(CrossFeverController.EVENT_CROSSFEVER_START, this.m_CrossData);
421	            
422	            // 設定CrossFever輪盤順序
423	            this.m_PlateMgr.IsCrossFever = true;
424	
425	        } catch (error) {
426	            error('CrossFever start failed:', error);
427	            this.ForceEndCrossFever();
428	        }        
429	    }
