513	    /**
514	     * 在指定位置顯示鎖定框
515	     */
516	    private async ShowLockFrameAt(position: number, isCross: boolean) {
517	        if (this.m_LockFrameNodes.has(position)) {
518	            return; // 該位置已有框架
519	        }
520	
521	        const frameNode = prefabPoolManager.GetNode(CrossFeverController.LOCK_FRAME_POOL_NAME, this.m_EffectContainer);
522	        if (!frameNode) return;
523	        frameNode.active = true;
524	
525	        // 設定位置
526	        const worldPosition = this.GetWheelWorldPosition(position);
527	        frameNode.setWorldPosition(worldPosition);
528	        frameNode.setScale(CrossFeverController.SCALE_NORMAL);
529	
530	        // 播放鎖定Frame動畫
531	        const crossFeverEmptyBingoFrame = frameNode.getComponent(CrossFeverEmptyBingoFrame);
532	        if (isCross) {
533	            // 設定CrossFever圖案(X)鎖定底圖顯示
534	            this.SetCrossFeverLockFrameShow(position, true);
535	            crossFeverEmptyBingoFrame.playCrossFrame();
536	        } else {
537	            crossFeverEmptyBingoFrame.playLockedFrame();
538	            frameNode.setScale(CrossFeverController.SCALE_POPUP_START);
539	
540	            // 停止該節點上的舊 tween（如果存在）
541	            this.StopNodeTween(frameNode);
542	
543	            // 使用 Promise 包裝 tween 來正確處理 await
544	            await new Promise<void>((resolve) => {
545	                const scaleTween = tween(frameNode)
546	                    .to(0.05, { scale: CrossFeverController.SCALE_NORMAL })
547	                    .call(() => {
548	                        this.SetCrossFeverLockFrameShow(position, true);
549	                        // 動畫完成後從追蹤中移除
550	                        this.m_activeTweens.delete(frameNode);
551	                        resolve();
552	                    })
553	                    .start();
554	
555	                // 追蹤這個 tween
556	                this.m_activeTweens.set(frameNode, scaleTween);
557	            });
558	        }
559	
560	        // 記錄框架節點
561	        this.m_LockFrameNodes.set(position, frameNode);
562	    }
