742	    /**
743	     * 檢查PreWin條件
744	     */
745	    private CheckPreWinCondition() {
746	        // log(`[CheckPreWinCondition] 開始檢查PreWin條件，當前狀態: ${CrossFeverState[this.m_CurrentState]}`);
747	        
748	        // 如果已經在PreWin狀態，就不要重複檢查
749	        if (this.m_CurrentState === CrossFeverState.PREWIN) {
750	            // log('[CheckPreWinCondition] 已在PreWin狀態，跳過重複檢查');
751	            return;
752	        }
753	
754	        // 如果全部輪盤都已經停止，跳過檢查
755	        if (this.m_PlateMgr.IsPlateStop()) {
756	            return;
757	        }
758	        
759	        const totalLocked = this.m_CrossData.LockedPositions.length;
760	        
761	        // log(`[CheckPreWinCondition] 位置統計: 總鎖定位置=${totalLocked}/${CrossFeverController.TOTAL_POSITIONS} (包含X型位置)`);
762	        
763	        if (totalLocked === CrossFeverController.TOTAL_POSITIONS - 1) {
764	            // 找出最後一個未鎖定的位置
765	            const lastUnlockedPos = this.FindLastUnlockedPosition();
766	            if (lastUnlockedPos !== -1) {
767	                // log(`[CheckPreWinCondition] ✅ PreWin條件達成（輪盤停止時觸發），剩餘位置: ${lastUnlockedPos}`);
768	                this.TriggerPreWin(lastUnlockedPos);
769	            } else {
770	                // warn('[CheckPreWinCondition] ⚠️ PreWin條件理論上達成但找不到未鎖定位置！');
771	            }
772	        } else {
773	            const needMore = CrossFeverController.TOTAL_POSITIONS - 1 - totalLocked;
774	            // log(`[CheckPreWinCondition] PreWin條件未達成，還需鎖定 ${needMore} 個位置`);
775	        }
776	    }
