import { _decorator, Component, Node, Vec3, tween, sp, log, error, warn, Tween } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { AudioManager } from '../Audio/AudioManager';
import { prefabPoolManager } from './PrefabPoolManager';
import { SinglePlateMgr } from '../SinglePlateMgr';
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import { Define } from 'db://astarte-framework/utilis';
import GameView from '../GameView';
import { CrossFeverEmptyBingoFrame } from './CrossFeverEmptyBingoFrame';
import { Common } from "../Common/Common";
import protocol from "@igs-arcade-division-rd2/uk_674_fruit_chachacha_proto/ar2fcccProto.js";
import { BaseSpine } from '../Spine/BaseSpine';

const { ccclass, property } = _decorator;

/**
 * CrossFever狀態枚舉
 */
export enum CrossFeverState {
    IDLE = 0,
    STARTING = 1,
    PLAYING = 2,
    PREWIN = 3,
    ENDING = 4
}

/**
 * CrossFever遊戲數據
 */
export interface CrossFeverData {
    CrossCenter: number;
    CrossSymbol: number;
    CrossPositions: number[];
    LockedPositions: number[];
}

@ccclass('CrossFeverController')
export class CrossFeverController extends Component {
    /** 
     * 總位置數量常數 (5x3 = 15個位置)
     */
    static readonly TOTAL_POSITIONS = 15;

    /** 
     * 鎖定框物件池模板名稱
     */
    static readonly LOCK_FRAME_POOL_NAME = 'LockFrame';

    /** 
     * CrossFever圖案(X)標準位置數量
     */
    static readonly CROSS_PATTERN_POSITIONS = 5;

    /** 
     * 網格行數 (5x3網格中的3行)
     */
    static readonly GRID_ROWS = 3;

    /** 
     * Spine動畫名稱 - 鎖定動畫
     */
    static readonly ANIMATION_LOCK = "Lock";

    /** 
     * Spine動畫名稱 - 宣告動畫
     */
    static readonly ANIMATION_DECLARE = "All";

    @property({type: Node, displayName: "CrossFever圖案(X)特效"})
    m_CrossEffectNode: Node = null;

    @property({type: Node, displayName: "鎖定框特效"})
    m_LockFrameNode: Node = null;

    @property({type: Node, displayName: "特效容器"})
    m_EffectContainer: Node = null;

    @property({type: BaseSpine, displayName: "宣告特效"})
    m_DeclareSpine: BaseSpine = null;

    /**@ch 輪盤管理器 */
    m_PlateMgr: SinglePlateMgr = null;

    // 事件名稱常量

    /** 
     * PreWin開始事件 - 當剩餘最後一個位置時觸發
     * 參數: { position: number, symbolId: number, source: string, duration: number }
     */
    static readonly EVENT_PREWIN_START = 'CrossFever_PrewinStart';

    /** 
     * PreWin結束事件 - PreWin動畫播放完畢時觸發
     * 參數: { position: number, symbolId: number, source: string }
     */
    static readonly EVENT_PREWIN_END = 'CrossFever_PrewinEnd';

    /** 
     * CrossFever開始事件 - CrossFever功能正式開始時觸發
     * 參數: CrossFeverData (包含CrossFever位置、鎖定位置、目標符號等資訊)
     */
    static readonly EVENT_CROSSFEVER_START = 'CrossFever_Start';

    /** 
     * CrossFever結束事件 - CrossFever功能完全結束時觸發
     * 參數: CrossFeverData (最終的遊戲數據)
     */
    static readonly EVENT_CROSSFEVER_END = 'CrossFever_End';

    /** 
     * 符號鎖定事件 - 新符號被鎖定時觸發
     * 參數: position (被鎖定的位置索引)
     */
    static readonly EVENT_LOCK_WHEEL = 'CrossFever_LockWheel';

    /** 
     * 單個輪盤停止事件 - 每個輪盤停止時觸發
     * 參數: wheelIndex (停止的輪盤索引)
     */
    static readonly EVENT_SINGLE_WHEEL_STOP = 'CrossFever_SingleWheelStop';

    /** 
     * 所有輪盤停止事件 - 一輪旋轉中所有輪盤都停止時觸發
     * 參數: 無
     */
    static readonly EVENT_ALL_WHEEL_STOPPED = 'CrossFever_AllWheelStopped';

    /**
     * 動畫間隔時間
     */
    static readonly ANIMATION_INTERVAL = 0.2;

    /**
     * 鎖定音效防抖時間窗口（秒）
     * 在此時間內只播放一次鎖定音效，避免多個符號同時鎖定時重複播放
     */
    static readonly LOCK_SOUND_RESET_TIME = 0.15;

    /** 
     * 正常縮放
     */
    static readonly SCALE_NORMAL = new Vec3(1.0, 1.0, 1.0);

    /** 
     * 動畫縮放
     */
    static readonly SCALE_ANIMATED = new Vec3(0.95, 0.95, 0.95);

    /** 
     * 彈出效果初始縮放 (放大)
     */
    static readonly SCALE_POPUP_START = new Vec3(1.3, 1.3, 1.3);

    // 私有屬性

    /** 
     * 當前CrossFever狀態
     * IDLE(0): 待機狀態，未啟動
     * STARTING(1): 啟動中，播放開場特效
     * PLAYING(2): 遊戲中，可接收輪盤停止事件
     * PREWIN(3): 預中獎狀態，播放PreWin特效
     * ENDING(4): 結束中，播放結束特效
     */
    private m_CurrentState: CrossFeverState = CrossFeverState.IDLE;

    /** 
     * 轉輪處理中標記
     * true: CrossFever正在處理轉輪事件（從OnNextSpinStart到OnAllWheelStopped完成）
     * false: 轉輪處理完成，可以安全進行狀態轉換
     */
    private m_IsProcessingWheel: boolean = false;

    /** 
     * CrossFever遊戲數據物件
     * 包含CrossFever位置、鎖定位置、目標符號、輪數、倍數等完整資訊
     */
    private m_CrossData: CrossFeverData;

    /** 
     * 上一輪新鎖定的位置陣列
     * 用於追蹤上一輪respin中新增的鎖定位置
    */
    private m_LastRoundLockedLocal: number[] = [];

    /** 
     * 本輪新鎖定的位置陣列
     * 記錄當前這一輪respin中新增的鎖定位置
    */
    private m_ThisRoundLockedLocal: number[] = [];

    /** 
     * PreWin輪盤索引陣列
     * 記錄觸發PreWin效果的輪盤位置
    */
    private m_PrewinWheelIndexes: number[] = [];

    /**@ch 是否需要在下一輪觸發PreWin */
    private m_ShouldTriggerPreWinNext: boolean = false;

    /**@ch 待觸發的PreWin位置 */
    private m_PendingPreWinPosition: number = -1;

    // 特效節點管理

    /** 
     * 鎖定框節點映射表
     * Key: 位置索引, Value: 該位置的鎖定框節點
     * 用於管理每個位置的鎖定框特效
    */
    private m_LockFrameNodes: Map<number, Node> = new Map();

    /** 
     * 動畫間隔時間
     */
    private m_AnimationDt = 0;

    /** 
     * 動畫旗標
     */
    private m_AnimationFlag = false;

    // 音效ID管理

    /** 
     * 背景音樂播放ID
     * -1表示未播放，其他值為AudioManager返回的播放ID
    */
    private m_BackgroundMusicId: number = -1;

    /**
     * 特效音效ID陣列
     * 記錄所有正在播放的特效音效ID，用於統一管理和停止
    */
    private m_EffectAudioIds: number[] = [];

    // 音效防抖機制

    /**
     * 鎖定音效已播放標記
     * true: 在時間窗口內已播放鎖定音效，跳過重複播放
     * false: 可以播放鎖定音效
     */
    private m_lockSoundPlayed: boolean = false;

    /**
     * 鎖定音效計時器
     * 記錄自上次播放鎖定音效以來的時間（秒）
     */
    private m_lockSoundTimer: number = 0;

    /**
     * Tween 管理 - 追蹤所有活躍的鎖定框縮放動畫
     * Key: 節點引用, Value: Tween 實例
     */
    private m_activeTweens: Map<Node, Tween<Node>> = new Map();

    private m_gameView: GameView = null;

    onDestroy() {
        this.UnregisterEvents();
        this.StopAllTweens(); // 新增：清理所有 tween
        this.Cleanup();
    }

    /**@ch 初始化 */
    public Init(gameView: GameView)
    {
        this.m_gameView = gameView;
        this.m_PlateMgr = this.m_gameView.SinglePlateMgr;

        // 初始化特效容器
        if (!this.m_EffectContainer) {
            this.m_EffectContainer = this.node.getChildByName('EffectContainer');
        }
    }

    /**
     * 註冊事件監聽
     */
    private RegisterEvents() {
        // 監聽輪盤停止事件
        eventManager.Register(CrossFeverController.EVENT_SINGLE_WHEEL_STOP, this);

        // 監聽所有輪盤停止事件
        eventManager.Register(CrossFeverController.EVENT_ALL_WHEEL_STOPPED, this);

        // 註冊物件池的Prefab
        if (this.m_LockFrameNode) {
            prefabPoolManager.RegisterTemplate(CrossFeverController.LOCK_FRAME_POOL_NAME, this.m_LockFrameNode, CrossFeverController.TOTAL_POSITIONS);
        }
    }

    /**
     * 取消事件監聽
     */
    private UnregisterEvents() {
        eventManager.UnRegister(CrossFeverController.EVENT_SINGLE_WHEEL_STOP, this);
        eventManager.UnRegister(CrossFeverController.EVENT_ALL_WHEEL_STOPPED, this);
    }

    /**
     * 事件處理方法
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[])
    {
        switch (event)
        {
            case CrossFeverController.EVENT_SINGLE_WHEEL_STOP:
                this.OnSingleWheelStop(args[0]);
                break;

            case CrossFeverController.EVENT_ALL_WHEEL_STOPPED:
                // 使用自執行異步函數確保正確的時序控制
                (async () => {
                    try {
                        await this.OnAllWheelStopped();
                    } catch (error) {
                        error('[CrossFeverController] OnAllWheelStopped 執行錯誤:', error);
                    }
                })();
                break;
        }
    }

    /**
     * 更新鎖定框節點縮放
     * @param dt 時間間隔
     */
    protected update(dt: number): void {
        // 只有在非IDLE狀態下才執行動畫邏輯，節省效能
        if (this.m_CurrentState === CrossFeverState.IDLE) {
            return;
        }

        // 處理鎖定音效防抖重置
        if (this.m_lockSoundPlayed) {
            this.m_lockSoundTimer += dt;
            if (this.m_lockSoundTimer >= CrossFeverController.LOCK_SOUND_RESET_TIME) {
                this.m_lockSoundPlayed = false;
                this.m_lockSoundTimer = 0;
            }
        }

        this.m_AnimationDt += dt;
        if (this.m_AnimationDt >= CrossFeverController.ANIMATION_INTERVAL) {
            this.m_AnimationDt = 0;
            this.m_AnimationFlag = !this.m_AnimationFlag;

            const targetScale = this.m_AnimationFlag ?
                CrossFeverController.SCALE_ANIMATED :
                CrossFeverController.SCALE_NORMAL;

            this.updateLineFramesScale(targetScale);
        }
    }

    /**
     * 更新鎖定框節點縮放
     * @param scale 縮放值
     */
    private updateLineFramesScale(scale: Vec3): void {
        this.m_LockFrameNodes.forEach((node, position) => {
            if (node) {
                node.setScale(scale);
            }
        });
    }

    /**
     * 設定CrossFever數據（從外部呼叫）
     */
    public SetCrossFeverData (data: CrossFeverData | protocol.ar2fcccProto.ICrossFeverInfo[]) {
        if (Array.isArray(data)) {
            // 處理 protocol.ar2fcccProto.ICrossFeverInfo[] 類型
            this.m_CrossData = {
                CrossCenter: data[0].CrossCenterPos || 0,
                CrossPositions: data[0].CrossLocalPos || [],
                LockedPositions: data[0].LockedPos || [],
                CrossSymbol: data[0].CrossSymbol || 0,
            };
        } else {
            // 處理 CrossFeverData 類型
            this.m_CrossData = {
                CrossCenter: data.CrossCenter,
                CrossPositions: data.CrossPositions,
                LockedPositions: data.LockedPositions,
                CrossSymbol: data.CrossSymbol,
            };
        }        
    }

    /**
     * 公開方法：開始CrossFever
     */
    public async StartCrossFever() {
        if (this.m_CurrentState !== CrossFeverState.IDLE) {
            warn('CrossFever already active');
            return;
        }
        log('Starting CrossFever');

        // 註冊事件監聽
        this.RegisterEvents();

        this.m_CurrentState = CrossFeverState.STARTING;        

        try {
            // 等待0.3秒
            await Define.Wait(this, 0.3);

            // 播放開場特效
            await this.DoCrossFeverStart();

            // 進入遊戲狀態
            this.m_CurrentState = CrossFeverState.PLAYING;

            // 發送開始事件
            eventManager.Dispatch(CrossFeverController.EVENT_CROSSFEVER_START, this.m_CrossData);

            // 設定CrossFever輪盤順序
            this.m_PlateMgr.IsCrossFever = true;

        } catch (error) {
            error('CrossFever start failed:', error);
            this.ForceEndCrossFever();
        }        
    }

    /**
     * 播放CrossFever開場特效
     */
    private async DoCrossFeverStart(): Promise<void> {
        // log('Playing CrossFever start effects');

        // 階段1：播放CrossFever圖案(X)特效
        this.PlayWheelFrameLightEffect(); // 播放全盤面的閃黃光效果
        await this.ShowCrossEffect();

        // 階段2：播放宣告特效
        this.PlayDeclareEffect();

        // 階段3：顯示CrossFever圖案(X)鎖定框 LeftBar要亮目前數量
        const count = this.m_CrossData.LockedPositions.length;
        this.LeftBarTurnOnLight(count);
        await this.ShowCrossLockedFrame();

        // 階段4：顯示已鎖定符號框
        await this.ShowLockedFrame();

        // 階段5：播放背景音樂
        this.PlayBackgroundMusic();

        // 階段6：設定Hold輪盤
        this.SetupHoldWheels();

        // log('CrossFever start effects completed');
    }

    /**
     * 顯示CrossFever圖案(X)特效
     */
    private async ShowCrossEffect(): Promise<void> {
        const node = this.m_CrossEffectNode;
        node.active = true;

        // 找到對應的轉輪座標
        const pos = this.GetWheelWorldPosition(this.m_CrossData.CrossCenter);

        // 將特效的座標設定到轉輪座標
        node.setWorldPosition(pos);

        // 進入CrossFever特效聲音
        AudioManager.Play(AudioManager.AudioClips.G97_Crose_In, false);

        // 播放spine動畫
        const skeleton = node.getComponent(sp.Skeleton);
        skeleton.enabled = true;
        await SpineKit.PlayAnimation(skeleton, CrossFeverController.ANIMATION_LOCK, false);
        node.active = false;
        skeleton.enabled = false;
    }

    /**
     * 顯示CrossFever圖案(X)鎖定框
     */
    private async ShowCrossLockedFrame(): Promise<void> {
        // 為CrossFever圖案(X)位置顯示鎖定框
        this.m_CrossData.CrossPositions.forEach(position => {
            this.ShowLockFrameAt(position, true);
        });

        // 播放鎖定CrossFever特效聲音
        AudioManager.Play(AudioManager.AudioClips.G97_Crose_Show, false);
        await Define.Wait(this, 1);
    }

    /**
     * 顯示已鎖定符號框
     */
    private async ShowLockedFrame(): Promise<void> {
        // 為已鎖定位置顯示框架
        this.m_CrossData.LockedPositions.forEach(position => {
            this.ShowLockFrameAt(position, false);
        });

        // 播放顯示音效
        AudioManager.Play(AudioManager.AudioClips.G97_Crose_Lock, false);
        await Define.Wait(this, 1);
    }

    /**
     * 在指定位置顯示鎖定框
     */
    private async ShowLockFrameAt(position: number, isCross: boolean) {
        if (this.m_LockFrameNodes.has(position)) {
            return; // 該位置已有框架
        }

        const frameNode = prefabPoolManager.GetNode(CrossFeverController.LOCK_FRAME_POOL_NAME, this.m_EffectContainer);
        if (!frameNode) return;
        frameNode.active = true;

        // 設定位置
        const worldPosition = this.GetWheelWorldPosition(position);
        frameNode.setWorldPosition(worldPosition);
        frameNode.setScale(CrossFeverController.SCALE_NORMAL);

        // 播放鎖定Frame動畫
        const crossFeverEmptyBingoFrame = frameNode.getComponent(CrossFeverEmptyBingoFrame);
        if (isCross) {
            // 設定CrossFever圖案(X)鎖定底圖顯示
            this.SetCrossFeverLockFrameShow(position, true);
            crossFeverEmptyBingoFrame.playCrossFrame();
        } else {
            crossFeverEmptyBingoFrame.playLockedFrame();
            frameNode.setScale(CrossFeverController.SCALE_POPUP_START);

            // 停止該節點上的舊 tween（如果存在）
            this.StopNodeTween(frameNode);

            // 使用 Promise 包裝 tween 來正確處理 await
            await new Promise<void>((resolve) => {
                const scaleTween = tween(frameNode)
                    .to(0.05, { scale: CrossFeverController.SCALE_NORMAL })
                    .call(() => {
                        this.SetCrossFeverLockFrameShow(position, true);
                        // 動畫完成後從追蹤中移除
                        this.m_activeTweens.delete(frameNode);
                        resolve();
                    })
                    .start();

                // 追蹤這個 tween
                this.m_activeTweens.set(frameNode, scaleTween);
            });
        }

        // 記錄框架節點
        this.m_LockFrameNodes.set(position, frameNode);
    }

    /**
     * 顯示宣告節點
     */
    private ShowDeclareSpine(): void {
        if (this.m_DeclareSpine && this.m_DeclareSpine.node) {
            this.m_DeclareSpine.node.active = true;
            this.m_DeclareSpine.Spine.enabled = true;
        }
    }

    /**
     * 隱藏宣告節點
     */
    private HideDeclareSpine(): void {
        if (this.m_DeclareSpine && this.m_DeclareSpine.node) {
            // 停止當前動畫
            this.m_DeclareSpine.Stop();
            // 隱藏節點
            this.m_DeclareSpine.node.active = false;

            // 停用Spine組件
            this.m_DeclareSpine.Spine.enabled = false;
        }
    }

    /**
     * 播放宣告特效
     */
    private async PlayDeclareEffect(): Promise<void> {
        // 確保宣告節點在表演前顯示
        this.ShowDeclareSpine();

        // 等待宣告動畫播放完成
        await this.m_DeclareSpine.PlayAnimation(CrossFeverController.ANIMATION_DECLARE, this.m_DeclareSpine.Spine, false);

        // 動畫播放完畢後隱藏節點
        this.HideDeclareSpine();
    }

    /**
     * 播放背景音樂
     */
    private PlayBackgroundMusic() {
        // 暫停背景音樂
        if (!this.m_gameView.IsFreeGame) {
            this.m_gameView.PauseMainGameBgm();
        }
        else {
            this.m_gameView.PauseFreeGameBgm();
        }

        // 播放CrossFever背景音樂
        this.m_BackgroundMusicId = AudioManager.PlayBackGround(AudioManager.AudioClips.G97_Crose_Bgm, true);
    }

    /**
     * 停止背景音樂
     */
    private StopBackgroundMusic() {
        // 停止CrossFever背景音樂
        if (this.m_BackgroundMusicId !== -1) {
            AudioManager.Stop(this.m_BackgroundMusicId);
            this.m_BackgroundMusicId = -1;
        }

        // 恢復背景音樂
        if (!this.m_gameView.IsFreeGame) {
            this.m_gameView.ResumeMainGameBgm();
        }
        else {
            this.m_gameView.ResumeFreeGameBgm();
        }
    }

    /**
     * 設定Hold輪盤
     */
    private SetupHoldWheels() {
        const holdArray = new Array(CrossFeverController.TOTAL_POSITIONS).fill(0);

        // 設定已鎖定位置為Hold 已包含CrossFever圖案(X)位置
        this.m_CrossData.LockedPositions.forEach(pos => {
            holdArray[pos] = 1;
        });

        // 應用Hold設定到輪盤系統
        if (this.m_PlateMgr) {
            // 設定已鎖定位置為Locked 已包含CrossFever圖案(X)位置
            this.m_CrossData.LockedPositions.forEach(pos => {
                this.m_PlateMgr.SetSymbolLockedByPosition(pos, true);
            });
        }

        // log('Hold wheels setup:', holdArray);
    }

    /**
     * 處理單個輪盤停止事件
     */
    private OnSingleWheelStop(wheelIndex: number) {
        // log(`[OnSingleWheelStop] 輪盤 ${wheelIndex} 停止，當前狀態: ${CrossFeverState[this.m_CurrentState]}`);

        if (this.m_CurrentState !== CrossFeverState.PLAYING && this.m_CurrentState !== CrossFeverState.PREWIN) {
            return;
        }

        // 檢查是否為新鎖定的符號
        // log(`[OnSingleWheelStop] 檢查輪盤 ${wheelIndex} 是否有新鎖定符號...`);
        this.CheckNewLockSymbol(wheelIndex);

        // 檢查PreWin條件
        // log(`[OnSingleWheelStop] 檢查PreWin觸發條件...`);
        this.CheckPreWinCondition();
    }

    /**
     * 檢查新鎖定符號
     */
    private CheckNewLockSymbol(wheelIndex: number) {
        // 如果該位置已經鎖定，跳過
        if (this.IsPositionLocked(wheelIndex)) {
            // log(`[CheckNewLockSymbol] 位置 ${wheelIndex} 已鎖定，跳過檢查`);
            return;
        }

        // 獲取輪盤符號
        if (this.m_PlateMgr && this.m_PlateMgr.PlateInfo) {
            const {col, row} = Common.GetColRowFromPosition(wheelIndex);

            // 從plateMgr的PlateInfo獲取符號ID
            const symbolId = this.m_PlateMgr.GetSymbolInPlateInfo(col, row);
            // log(`[CheckNewLockSymbol] 位置 ${wheelIndex}(${col},${row}) 符號ID: ${symbolId}, 目標符號: ${this.m_CrossData.CrossSymbol}`);

            if (symbolId === this.m_CrossData.CrossSymbol) {
                // log(`[CheckNewLockSymbol] ✅ 符號匹配！準備鎖定位置 ${wheelIndex}`);
                this.LockNewSymbol(wheelIndex);
            } else {
                // log(`[CheckNewLockSymbol] 符號未匹配，不鎖定`);
            }
        } else {
            error('[CheckNewLockSymbol] ❌ PlateMgr或PlateInfo未找到！');
        }
    }

    /**
     * 鎖定新符號
     */
    private LockNewSymbol(position: number) {
        // log(`[LockNewSymbol] 🔒 開始鎖定新符號，位置: ${position}`);

        // 添加到鎖定列表
        this.m_CrossData.LockedPositions.push(position);
        this.m_ThisRoundLockedLocal.push(position);

        const totalLocked = this.m_CrossData.LockedPositions.length;
        // log(`[LockNewSymbol] 鎖定數量更新: 總鎖定位置=${totalLocked}/${CrossFeverController.TOTAL_POSITIONS} (包含X型位置)`);

        // 顯示鎖定框
        this.ShowLockFrameAt(position, false);

        // 播放鎖定音效（防抖機制）
        if (!this.m_lockSoundPlayed) {
            this.m_lockSoundPlayed = true;
            this.m_lockSoundTimer = 0;
            AudioManager.Play(AudioManager.AudioClips.G97_Crose_Show, false);
        }

        // 發送鎖定事件
        eventManager.Dispatch(CrossFeverController.EVENT_LOCK_WHEEL, position);
        // log(`[LockNewSymbol] ✅ 鎖定事件已發送`);

        // LeftBar要移動獎勵燈
        const count = this.m_CrossData.LockedPositions.length;
        this.LeftBarMoveRewardLight(count - 1, count);

        // log(`[LockNewSymbol] 🎯 符號鎖定完成！位置 ${position} 已成功鎖定`);
    }

    /**
     * 檢查PreWin條件
     */
    private CheckPreWinCondition() {
        // log(`[CheckPreWinCondition] 開始檢查PreWin條件，當前狀態: ${CrossFeverState[this.m_CurrentState]}`);

        // 如果已經在PreWin狀態，就不要重複檢查
        if (this.m_CurrentState === CrossFeverState.PREWIN) {
            // log('[CheckPreWinCondition] 已在PreWin狀態，跳過重複檢查');
            return;
        }

        // 如果全部輪盤都已經停止，跳過檢查
        if (this.m_PlateMgr.IsPlateStop()) {
            return;
        }

        const totalLocked = this.m_CrossData.LockedPositions.length;

        // log(`[CheckPreWinCondition] 位置統計: 總鎖定位置=${totalLocked}/${CrossFeverController.TOTAL_POSITIONS} (包含X型位置)`);

        if (totalLocked === CrossFeverController.TOTAL_POSITIONS - 1) {
            // 找出最後一個未鎖定的位置
            const lastUnlockedPos = this.FindLastUnlockedPosition();
            if (lastUnlockedPos !== -1) {
                // log(`[CheckPreWinCondition] ✅ PreWin條件達成（輪盤停止時觸發），剩餘位置: ${lastUnlockedPos}`);
                this.TriggerPreWin(lastUnlockedPos);
            } else {
                // warn('[CheckPreWinCondition] ⚠️ PreWin條件理論上達成但找不到未鎖定位置！');
            }
        } else {
            const needMore = CrossFeverController.TOTAL_POSITIONS - 1 - totalLocked;
            // log(`[CheckPreWinCondition] PreWin條件未達成，還需鎖定 ${needMore} 個位置`);
        }
    }

    /**
     * 設定待觸發PreWin標記（不立即觸發）
     */
    private SetPendingPreWinIfNeeded() {
        // log(`[SetPendingPreWinIfNeeded] 檢查是否需要設定待觸發PreWin`);

        // 如果已經在PreWin狀態，就不要重複檢查
        if (this.m_CurrentState === CrossFeverState.PREWIN) {
            // log('[SetPendingPreWinIfNeeded] 已在PreWin狀態，跳過設定');
            return;
        }

        const totalLocked = this.m_CrossData.LockedPositions.length;

        // log(`[SetPendingPreWinIfNeeded] 位置統計: 總鎖定位置=${totalLocked}/${CrossFeverController.TOTAL_POSITIONS} (包含X型位置)`);

        if (totalLocked === CrossFeverController.TOTAL_POSITIONS - 1) {
            // 下一輪就是最後一個位置，設定待觸發標記
            const lastUnlockedPos = this.FindLastUnlockedPosition();
            if (lastUnlockedPos !== -1) {
                // log(`[SetPendingPreWinIfNeeded] ✅ 設定待觸發PreWin標記，目標位置: ${lastUnlockedPos}`);
                this.m_ShouldTriggerPreWinNext = true;
                this.m_PendingPreWinPosition = lastUnlockedPos;
            } else {
                // warn('[SetPendingPreWinIfNeeded] ⚠️ PreWin條件理論上達成但找不到未鎖定位置！');
            }
        } else {
            const needMore = CrossFeverController.TOTAL_POSITIONS - 1 - totalLocked;
            // log(`[SetPendingPreWinIfNeeded] PreWin條件未達成，還需鎖定 ${needMore} 個位置才會觸發PreWin`);
        }
    }

    /**
     * 下一輪開始時的處理（供GameView調用）
     */
    public OnNextSpinStart() {
        // 設置轉輪處理中標記
        this.m_IsProcessingWheel = true;
        log(`[OnNextSpinStart] 🎰 開始處理轉輪，設置處理標記為 true`);

        // 重置音效防抖狀態，確保新一輪可以播放鎖定音效
        this.m_lockSoundPlayed = false;
        this.m_lockSoundTimer = 0;

        if (this.m_ShouldTriggerPreWinNext && this.m_PendingPreWinPosition !== -1) {
            // log(`[OnNextSpinStart] 觸發待處理的PreWin，位置: ${this.m_PendingPreWinPosition}`);

            // 添加小延遲確保UI準備好，營造"即將中獎"的緊張感
            this.scheduleOnce(() => {
                // log(`[OnNextSpinStart] 正式觸發PreWin，營造「下一輪即將中獎」的期待感`);
                this.TriggerPreWin(this.m_PendingPreWinPosition);

                // 重置標記
                this.m_ShouldTriggerPreWinNext = false;
                this.m_PendingPreWinPosition = -1;
            }, 0.2); // 200ms延遲，讓玩家感受到轉換
        } else {
            // log(`[OnNextSpinStart] 無待觸發的PreWin`);
        }
    }

    /**
     * 找出最後一個未鎖定位置
     */
    private FindLastUnlockedPosition(): number {
        // LockedPositions 已經包含 CrossPositions，不需要重複合併
        const lockedPositions = this.m_CrossData.LockedPositions;

        for (let i = 0; i < CrossFeverController.TOTAL_POSITIONS; i++) {
            if (!lockedPositions.includes(i)) {
                return i;
            }
        }
        return -1;
    }

    /**
     * @ch 設定CrossFever圖案鎖定Frame顯示
     * @param position 位置 (0~14)，-1表示全部
     * @param isShow 是否顯示
     */
    SetCrossFeverLockFrameShow(position: number, isShow: boolean): void
    {
        this.m_gameView.FrameUIControl.SetCrossFeverLockFrameShow(position, isShow);
    }

    /**
     * 觸發PreWin
     */
    private TriggerPreWin(position: number) {
        log(`[TriggerPreWin] 🎯 正式觸發PreWin！位置: ${position}, 目標符號: ${this.m_CrossData.CrossSymbol}`);
        log(`[TriggerPreWin] 狀態轉換: ${CrossFeverState[this.m_CurrentState]} → PREWIN`);

        this.m_CurrentState = CrossFeverState.PREWIN;
        this.m_PrewinWheelIndexes = [position];

        // 發送PreWin開始事件
        const preWinData = {
            position: position,
            symbolId: this.m_CrossData.CrossSymbol,
            source: 'crossfever',
            duration: 2.0
        };

        eventManager.Dispatch(CrossFeverController.EVENT_PREWIN_START, preWinData);

        // log(`[TriggerPreWin] ✅ PreWin事件已發送，預計持續時間: ${preWinData.duration}秒`);

        // 使用PreWinController播放預中獎符號效果
        if (this.m_gameView && this.m_gameView.PreWinController) {
            // log(`[TriggerPreWin] 調用PreWinController.PlayPreWinSymbol(${position}, true)`);
            this.m_gameView.PreWinController.PlayPreWinSymbol(position, true);
        } else {
            // error('[TriggerPreWin] ❌ PreWinController未找到，無法播放預中獎效果！');
        }
    }

    /**
     * 結束PreWin
     */
    private async EndPreWin(position: number) {
        // log(`[EndPreWin] 準備結束PreWin，位置: ${position}, 當前狀態: ${CrossFeverState[this.m_CurrentState]}`);

        if (this.m_CurrentState !== CrossFeverState.PREWIN) {
            // log(`[EndPreWin] 非PreWin狀態，跳過結束處理`);
            return;
        }

        log(`[EndPreWin] 狀態轉換: PREWIN → PLAYING`);
        this.m_CurrentState = CrossFeverState.PLAYING;
        this.m_PrewinWheelIndexes = [];

        // 發送PreWin結束事件
        const preWinData = {
            position: position,
            symbolId: this.m_CrossData.CrossSymbol,
            source: 'crossfever'
        };

        eventManager.Dispatch(CrossFeverController.EVENT_PREWIN_END, preWinData);

        // log(`[EndPreWin] ✅ PreWin結束事件已發送`);

        // 停止PreWinController的預中獎符號效果
        if (this.m_gameView && this.m_gameView.PreWinController) {
            // log(`[EndPreWin] 調用PreWinController.StopPreWinSymbol()`);
            await this.m_gameView.PreWinController.StopPreWinSymbol();
            log(`[EndPreWin] ✅ PreWin符號效果已停止`);
        } else {
            error('[EndPreWin] ❌ PreWinController未找到，無法停止預中獎效果！');
        }
    }

    /**
     * 處理所有輪盤停止事件
     */
    private async OnAllWheelStopped() {
        // log('OnAllWheelStopped');

        if (this.m_PrewinWheelIndexes.length > 0) {
            await this.EndPreWin(this.m_PrewinWheelIndexes[0]);
        }

        if (this.m_CurrentState !== CrossFeverState.PLAYING) return;

        // 檢查是否有新的鎖定符號
        const hasNewLocked = this.m_ThisRoundLockedLocal.length > 0;

        if (hasNewLocked) {
            log(`[OnAllWheelStopped] 本輪新增鎖定位置: [${this.m_ThisRoundLockedLocal.join(', ')}]`);

            // 更新上輪鎖定記錄
            this.m_LastRoundLockedLocal = [...this.m_ThisRoundLockedLocal];
            // 只把本輪鎖定符號設定為Hold
            this.m_ThisRoundLockedLocal.forEach(pos => {
                this.m_PlateMgr.SetSymbolLockedByPosition(pos, true);
            });

            // 重置本輪鎖定記錄
            this.m_ThisRoundLockedLocal = [];

            const currentTotal = this.m_CrossData.LockedPositions.length;
            // log(`[OnAllWheelStopped] 當前總鎖定數: ${currentTotal}/${CrossFeverController.TOTAL_POSITIONS} (包含X型位置)`);

            // 檢查是否達到全盤獎條件
            if (this.CheckFullScreenWin()) {
                // 達成全盤獎條件，直接結束遊戲
                this.ScheduleGameEnd();
            } else {
                // log(`[OnAllWheelStopped] 準備檢查下一輪PreWin觸發條件...`);
                // 設定待觸發PreWin標記，不立即觸發
                this.SetPendingPreWinIfNeeded();
            }
        } else {
            // 沒有新鎖定，檢查遊戲結束條件
            this.CheckGameEndCondition();
        }

        // 轉輪處理完成，重置處理標記
        this.m_IsProcessingWheel = false;
        log(`[OnAllWheelStopped] 🏁 轉輪處理完成，重置處理標記為 false`);
    }

    /**
     * 檢查全盤獎條件
     */
    private CheckFullScreenWin(): boolean {
        const totalLocked = this.m_CrossData.LockedPositions.length;
        return totalLocked >= CrossFeverController.TOTAL_POSITIONS;
    }

    /**
     * 檢查遊戲結束條件
     */
    private CheckGameEndCondition() {
        // 根據遊戲規則決定是否結束
        // 這裡可以添加其他結束條件的檢查

        // log('Checking game end condition');
        this.ScheduleGameEnd();
    }

    /**
     * 安排遊戲結束
     */
    private async ScheduleGameEnd() {
        // 延遲一段時間後結束遊戲
        await Define.Wait(this, 1.0);
        this.EndCrossFever();
    }

    /**
     * 結束CrossFever
     */
    private async EndCrossFever() {
        if (this.m_CurrentState === CrossFeverState.IDLE) return;

        log('Ending CrossFever');
        this.m_CurrentState = CrossFeverState.ENDING;

        try {

            // 結束PreWin
            if (this.m_PrewinWheelIndexes.length > 0) {
                await this.EndPreWin(this.m_PrewinWheelIndexes[0]);
            }

            // 播放結束特效
            await this.PlayEndEffects();

            // 重要：通知GameView結束CrossFever模式
            if (this.m_gameView) {
                this.m_gameView.IsCrossFever = false;
                log('[CrossFeverController] 已通知GameView結束CrossFever模式');
            }

            // 清理資源
            this.Cleanup();

            // 發送結束事件
            eventManager.Dispatch(CrossFeverController.EVENT_CROSSFEVER_END, this.m_CrossData);

            // 重置狀態
            this.m_CurrentState = CrossFeverState.IDLE;

        } catch (error) {
            error('CrossFever end failed:', error);
            this.ForceEndCrossFever();
        }

        // 設定輪盤順序
        this.m_PlateMgr.IsCrossFever = false;

        this.UnregisterEvents();
    }

    /**
     * 播放結束特效
     */
    private async PlayEndEffects(): Promise<void> {
        // 停止背景音樂
        this.StopBackgroundMusic();
    }

    /**
     * 強制結束CrossFever
     */
    private ForceEndCrossFever() {
        // warn('Force ending CrossFever');

        // 重要：強制結束時也要通知GameView
        if (this.m_gameView) {
            this.m_gameView.IsCrossFever = false;
            log('[CrossFeverController] 強制結束時已通知GameView結束CrossFever模式');
        }

        // 強制結束時重置轉輪處理標記
        this.m_IsProcessingWheel = false;
        log('[CrossFeverController] 強制結束時重置轉輪處理標記為 false');

        this.Cleanup();
        this.m_CurrentState = CrossFeverState.IDLE;
    }

    /**
     * 清理資源
     */
    private Cleanup() {

        // 停止所有 tween 動畫
        this.StopAllTweens();

        // 隱藏宣告特效節點
        this.HideDeclareSpine();

        // 清理鎖定框節點
        this.m_LockFrameNodes.forEach((node, position) => {
            if (node && node.isValid) {
                // 確保該節點的 tween 已停止
                this.StopNodeTween(node);
                prefabPoolManager.ReturnNode(CrossFeverController.LOCK_FRAME_POOL_NAME, node);
            }
            this.SetCrossFeverLockFrameShow(position, false);
        });
        this.m_LockFrameNodes.clear();

        // 重置所有符號鎖定狀態
        this.m_PlateMgr.ResetAllSymbolsLocked();

        // 停止音效
        this.m_EffectAudioIds.forEach(audioId => {
            AudioManager.Stop(audioId);
        });
        this.m_EffectAudioIds = [];

        this.StopBackgroundMusic();

        // 重置數據
        this.m_CrossData = null;
        this.m_ThisRoundLockedLocal = [];
        this.m_LastRoundLockedLocal = [];
        this.m_PrewinWheelIndexes = [];

        // 重置待觸發標記
        this.m_ShouldTriggerPreWinNext = false;
        this.m_PendingPreWinPosition = -1;

        // 重置音效防抖狀態
        this.m_lockSoundPlayed = false;
        this.m_lockSoundTimer = 0;

        log('CrossFever cleanup completed');
    }

    /**
     * 檢查位置是否已鎖定
     */
    private IsPositionLocked(position: number): boolean {
        return this.m_CrossData.CrossPositions.includes(position) || this.m_CrossData.LockedPositions.includes(position);
    }

    /**
     * 獲取輪盤初始世界座標
     */
    private GetWheelWorldPosition(position: number): Vec3 {
        // 嘗試從 SinglePlateMgr 獲取位置
        if (this.m_PlateMgr) {
            const {col, row} = Common.GetColRowFromPosition(position);
            const wheelPos = this.m_PlateMgr.GetSymbolInitWorldPosition(col, row);
            if (wheelPos) {
                return wheelPos;
            }
        }

        // 如果無法獲取輪盤位置
        return Vec3.ZERO;
    }

    /**
     * 檢查PreWin輪盤索引
     */
    public CheckPrewinWheelIndexes(): number[] {
        if (!this.m_CrossData) return [];

        const lockedCount = this.m_CrossData.LockedPositions.length;

        if (lockedCount === CrossFeverController.TOTAL_POSITIONS - 1) {
            const lastUnlockedPos = this.FindLastUnlockedPosition();
            if (lastUnlockedPos !== -1) {
                return [lastUnlockedPos];
            }
        }

        return [];
    }

    /**
     * 獲取當前狀態
     */
    public GetCurrentState(): CrossFeverState {
        return this.m_CurrentState;
    }

    /**
     * 獲取CrossFever數據
     */
    public GetCrossFeverData(): CrossFeverData {
        return this.m_CrossData;
    }

    /**
     * 獲取鎖定符號數量
     */
    public GetLockedCount(): number {
        if (!this.m_CrossData) return 0;
        return this.m_CrossData.LockedPositions.length;
    }

    /**
     * 獲取目標符號ID
     */
    public GetTargetSymbolId(): number {
        return this.m_CrossData ? this.m_CrossData.CrossSymbol : 0;
    }

    /**
     * 檢查是否為CrossFever遊戲
     */
    public IsCrossFeverActive(): boolean {
        return this.m_CurrentState !== CrossFeverState.IDLE;
    }

    /**
     * 檢查是否正在處理轉輪
     * @returns true 如果正在處理轉輪（OnNextSpinStart到OnAllWheelStopped完成期間）
     */
    public IsProcessingWheel(): boolean {
        return this.m_IsProcessingWheel;
    }

    /**
     * 強制停止CrossFever（從外部呼叫）
     */
    public ForceStop() {
        log('[CrossFeverController] 收到外部強制停止請求');
        this.ForceEndCrossFever();
    }

    /**
     * 左邊Bar亮燈
     * @param count 數量
     */
    LeftBarTurnOnLight(count: number)
    {
        if (this.m_gameView.OddsTableManager)
        {
            this.m_gameView.OddsTableManager.SetPurpleFrameActive(count);
        }
    }

    /**
     * 左邊Bar移動獎勵燈
     * @param startNumber 開始數量
     * @param endNumber 結束數量
     */
    LeftBarMoveRewardLight(startNumber: number, endNumber: number)
    {
        if (this.m_gameView.OddsTableManager && startNumber >= 3 && endNumber > startNumber)
        {
            this.m_gameView.OddsTableManager.MoveRewardLight(startNumber, endNumber, 0.5);
        }
    }

    /**
     * @ch 從斷線重連恢復鎖定框（專用於 UnshowPrepareState）
     * 此方法會重用現有的鎖定框邏輯，但跳過開場動畫，直接恢復到可遊玩狀態
     */
    public async RestoreLockedFramesFromUnshow(): Promise<void>
    {
        if (!this.m_CrossData) {
            error("[CrossFeverController] RestoreLockedFramesFromUnshow: CrossData 未設定");
            return;
        }

        if (this.m_CurrentState !== CrossFeverState.IDLE) {
            warn("[CrossFeverController] RestoreLockedFramesFromUnshow: 非 IDLE 狀態，強制重置");
            this.ForceEndCrossFever();
        }

        log("[CrossFeverController] 開始恢復 CrossFever 鎖定框狀態");

        try {
            // 1. 設定為啟動中狀態
            this.m_CurrentState = CrossFeverState.STARTING;

            // 2. 註冊事件監聽（重要：確保輪盤事件能被接收）
            this.RegisterEvents();

            // 3. 恢復 CrossFever 圖案（X）鎖定框
            await this.RestoreCrossLockedFrames();

            // 4. 恢復已鎖定符號框
            await this.RestoreAlreadyLockedFrames();

            // 5. 設定輪盤鎖定狀態
            this.SetupHoldWheels();

            // 6. 設定 LeftBar 燈光顯示
            const count = this.m_CrossData.LockedPositions.length;
            this.LeftBarTurnOnLight(count);

            // 7. 播放背景音樂
            this.PlayBackgroundMusic();

            // 8. 設定 CrossFever 輪盤順序
            this.m_PlateMgr.IsCrossFever = true;

            // 9. 檢查是否需要恢復到 PreWin 狀態
            const totalLocked = this.m_CrossData.LockedPositions.length;
            if (totalLocked === CrossFeverController.TOTAL_POSITIONS - 1) {
                // 達到 PreWin 條件（14個位置已鎖定），恢復 PreWin 狀態
                const lastUnlockedPos = this.FindLastUnlockedPosition();
                if (lastUnlockedPos !== -1) {
                    // log(`[CrossFeverController] 🎯 恢復到 PreWin 狀態，最後位置: ${lastUnlockedPos}`);
                    this.m_CurrentState = CrossFeverState.PREWIN;
                    this.m_PrewinWheelIndexes = [lastUnlockedPos];

                    // 發送 PreWin 開始事件
                    const preWinData = {
                        position: lastUnlockedPos,
                        symbolId: this.m_CrossData.CrossSymbol,
                        source: 'crossfever_restore',
                        duration: 2.0
                    };
                    eventManager.Dispatch(CrossFeverController.EVENT_PREWIN_START, preWinData);

                    // 使用PreWinController播放預中獎符號效果
                    if (this.m_gameView && this.m_gameView.PreWinController) {
                        this.m_gameView.PreWinController.PlayPreWinSymbol(lastUnlockedPos, true);
                        // log(`[CrossFeverController] ✅ PreWin 視覺效果已啟動`);
                    } else {
                        error('[CrossFeverController] ❌ PreWinController未找到，無法播放預中獎效果！');
                    }
                } else {
                    error('[CrossFeverController] ❌ PreWin條件達成但找不到未鎖定位置！');
                    this.m_CurrentState = CrossFeverState.PLAYING;
                }
            } else {
                // 未達到 PreWin 條件，直接進入遊戲狀態
                this.m_CurrentState = CrossFeverState.PLAYING;
                // log(`[CrossFeverController] 恢復到 PLAYING 狀態，目前鎖定位置數: ${totalLocked}`);
            }

            // log("[CrossFeverController] ✅ CrossFever 鎖定框狀態恢復完成");

        } catch (error) {
            error("[CrossFeverController] ❌ 恢復 CrossFever 狀態失敗:", error);
            this.ForceEndCrossFever();
        }
    }

    /**
     * @ch 恢復 CrossFever 圖案（X）鎖定框
     */
    private async RestoreCrossLockedFrames(): Promise<void>
    {
        // log("[CrossFeverController] 恢復 CrossFever 圖案鎖定框");

        // 為 CrossFever 圖案（X）位置顯示鎖定框
        for (const position of this.m_CrossData.CrossPositions) {
            await this.ShowLockFrameAt(position, true);
        }
    }

    /**
     * @ch 恢復已鎖定符號框
     */
    private async RestoreAlreadyLockedFrames(): Promise<void>
    {
        // log("[CrossFeverController] 恢復已鎖定符號框");

        // 為已鎖定位置顯示框架（排除 CrossFever 圖案位置，避免重複）
        const crossPositions = new Set(this.m_CrossData.CrossPositions);

        for (const position of this.m_CrossData.LockedPositions) {
            if (!crossPositions.has(position)) {
                await this.ShowLockFrameAt(position, false);
            }
        }
    }

    /**
     * @ch 播放全盤面的閃黃光效果
     * @param isAutoStop 是否自動停止
     */
    private async PlayWheelFrameLightEffect(isAutoStop: boolean = true) : Promise<void>
    {
        return this.m_gameView.PreWinController.PlayWheelFrameLightEffect(isAutoStop);
    }

    /**
     * 停止指定節點上的所有 Tween
     * @param node 目標節點
     */
    private StopNodeTween(node: Node): void {
        if (!node || !node.isValid) {
            return;
        }

        // 停止並移除追蹤的 tween
        if (this.m_activeTweens.has(node)) {
            const existingTween = this.m_activeTweens.get(node);
            existingTween?.stop();
            this.m_activeTweens.delete(node);
        }

        // 同時停止 Cocos 層面的所有 tween
        Tween.stopAllByTarget(node);
    }

    /**
     * 停止所有追蹤的 Tween
     */
    private StopAllTweens(): void {
        this.m_activeTweens.forEach((tweenInstance, node) => {
            if (tweenInstance) {
                tweenInstance.stop();
            }
        });
        this.m_activeTweens.clear();

        log('[CrossFeverController] All tweens stopped and cleared');
    }
}

