        [2, 3, 4, 5, 7, 10, 12, 15, 20, 30, 40, 50]   // FG 賠率
    ];

    // 全盤獎表：MG 和 FG 的全盤獎資料
    // 第一行：MG 全盤獎 (3x, 4x, 5x, 6x, 7x, 8x, 9x, 10x, 11x, 12x, 13x, 14x)
    // 第二行：FG 全盤獎 (3x, 4x, 5x, 6x, 7x, 8x, 9x, 10x, 11x, 12x, 13x, 14x)
