    ];

    /**
     * 根據賠率獲取對應的贏分類型
     * @param odds 賠率
     * @returns 對應的WinType
     */
    static GetWinType( odds: number ): WinType
    {
        // 判斷是否為0（無贏分）
        if ( odds === 0 )
        {
            return WinType.NoWin;
        }

        // 使用PlateEftOdds陣列作為分界點進行判斷
        const [youWinThreshold, bigWinThreshold, megaWinThreshold, superWinThreshold] = this.PlateEftOdds;

        if ( odds < youWinThreshold ) // 0 < odds < 5
        {
            return WinType.NormalWin;
        }
        else if ( odds < bigWinThreshold ) // 5 <= odds < 10
        {
            return WinType.YouWin;
        }
        else if ( odds < megaWinThreshold ) // 10 <= odds < 25
        {
            return WinType.BigWin;
        }
        else if ( odds < superWinThreshold ) // 25 <= odds < 50
        {
            return WinType.MegaWin;
        }
        else // 50 <= odds
        {
            return WinType.SuperWin;
        }
    }

