/**
 * 檢查位置是否存在於 8 個方向
 * @param pos 位置
 * @returns 8 個方向的存在性陣列
 */
private CheckPosExist(pos: number): boolean[] {
    const posExist = [false, false, false, false, false, false, false, false];

    const hasTop = pos % this.REEL_ROWS !== 0;        // 0,3,6,9,12
    const hasDown = pos % this.REEL_ROWS !== this.LAST_ROW_INDEX;       // 2,5,8,11,14
    const hasLeft = pos >= this.REEL_ROWS;            // 0,1,2
    const hasRight = pos <= (this.TOTAL_POSITIONS - this.REEL_ROWS - 1);          // 12,13,14

    posExist[BombEffectSign.Up] = hasTop;
    posExist[BombEffectSign.Down] = hasDown;
    posExist[BombEffectSign.Left] = hasLeft;
    posExist[BombEffectSign.Right] = hasRight;
    posExist[BombEffectSign.LeftUp] = hasTop && hasLeft;
    posExist[BombEffectSign.LeftDown] = hasDown && hasLeft;
    posExist[BombEffectSign.RightUp] = hasTop && hasRight;
    posExist[BombEffectSign.RightDown] = hasDown && hasRight;

    return posExist;
}

