private async PlayBombEffectByData(callback: Function): Promise<void> {
    const promises = this.m_bombInfos.map(async (info) => {
        // log('FeatureBomb playBombEffectByData:', info);

        // 等待炸彈效果開始前的準備時間
        await this.WaitForSeconds(this.BOMB_EFFECT_PREPARE_TIME);

        // 觸發開始事件
        this.eventStartBombEffect.forEach(callback => {
            if (callback) callback(info.bomb_pos);
        });

        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_START);

        // 隱藏原符號
        this.ShowSymbol(info.bomb_pos, false);

        // 根據炸彈類型播放不同音效和更換符號
        if (info.bomb_id === BombSymbolId.RedBomb) {
            AudioManager.Play(this.BOMB_JIUGONGGE, false, null, 1);
            this.ChangeSymbol(BombSymbolId.RedBomb, info.bomb_pos);
        } else {
            AudioManager.Play(this.BOMB_CROSS, false, null, 1);
            this.ChangeSymbol(BombSymbolId.BlackBomb, info.bomb_pos);
        }

        // 播放炸彈爆炸動畫
        const callback1 = () => {

        };
        await this.PlayBombEffect(info.bomb_id, info.bomb_pos, callback1);

        eventManager.Dispatch(FeatureBomb.EVENT_BOMB_FIRE_START);

        // 播放火花效果
        const callback2 = () => {
            this.ShowSymbol(info.bomb_pos, true);
            this.ChangeSymbol(info.change_id, info.bomb_pos);
            info.change_pos.forEach((pos) => {
                this.ChangeSymbol(info.change_id, pos);
            });
        };
        await this.PlayFireEffect(info.bomb_id, info.bomb_pos, callback2);
    });

    await Promise.all(promises);

    // 觸發停止事件
    this.eventStopBombEffect.forEach(callback => {
        if (callback) callback();
    });

    eventManager.Dispatch(FeatureBomb.EVENT_BOMB_STOP);

    if (callback) {
        callback();
    }
}

