 * 播放炸彈功能
 */
private async PlayBombFeature(): Promise<void>
{
    if ( !this.m_gameView.FeatureBomb )
    {
        error( "FeatureShowState: FeatureBomb component not found" );
        return;
    }

    log( "FeatureShowState: Playing bomb feature" );

    // 設定炸彈功能完成回調
    this.m_gameView.FeatureBomb.eventFinished.push( () => {
        log( "FeatureShowState: Bomb feature finished" );
        this.OnBombFeatureFinished();
    } );

    // 開始炸彈功能
    this.m_gameView.FeatureBomb.StartFeature( this.m_bombData );

    // 播放炸彈功能
    await this.m_gameView.FeatureBomb.PlayFeature();
}

/**
 * 播放預設特色功能
 */
private PlayDefaultFeatureDemo() : boolean
{
    if ( !newExtraManager.IsFeaturesDemo || this.m_gameView.IsAutoShowFeatures)
    {
        return false;
    }

    if (!this.IsNeedFeatureDemo)
    {
        return false;
    }

    this.IsNeedFeatureDemo = false;

    newBottombarManager.CanPlayFeaturesDemo( true );
    this.m_gameView.IsAutoShowFeatures = true;
    newBottombarManager.SetBarNodeVisiable( true );
    if ( this.m_gameView.GameIntro )
    {
        this.m_gameView.GameIntro.forEach(intro => intro.node.active = false);
    }
    // this.m_gameView.BuyBonus.SetBuyBtnVisible( true );
    newExtraManager.AutoShowFeatures();

    log( "FeatureShowState: Playing default feature" );
    return true;
}

