private async PlayFireEffect(bombId: number, bombLocation: number, callback: Function): Promise<void> {
    const redBombSpineList = ["T", "D", "L", "R", "LT", "LD", "RT", "RD"];
    const blackBombSpineList = ["T", "D", "L", "R"];
    const bombSpineList = bombId === BombSymbolId.RedBomb ? redBombSpineList : blackBombSpineList;

    const bombPos = this.GetBlockWorldPosition(bombLocation);
    const posExist = this.CheckPosExist(bombLocation);

    // log('PlayFireEffect posExist:', posExist);

    let regEvent = false;
    const effectPromises: Promise<void>[] = [];

    // 增加中心爆炸效果
    const centerEffectPromise = this.PlayCenterFireEffect(bombLocation, () => {
        if (!regEvent) {
            regEvent = true;
            log('Bomb Center Fire Hit event trigger');
            if (callback) callback();
        }
    });
    effectPromises.push(centerEffectPromise);

    // 播放方向性火花效果
    for (let index = 0; index < bombSpineList.length; index++) {
        const animationName = bombSpineList[index];

        if (!posExist[index]) {
            continue;
        }

        // 使用通用方法播放方向性火花動畫
        const effectPromise = this.PlaySingleFireAnimation(animationName, bombPos, () => {
            if (!regEvent) {
                regEvent = true;
                log('Bomb Fire Hit event trigger');
                if (callback) callback();
            }
        });

        effectPromises.push(effectPromise);
    }

    // 等待所有特效動畫完成
    await Promise.all(effectPromises);
}

